/**
 * Remove stale Ui* imports after codemod-ui-to-native.
 * Usage: tsx scripts/cleanup-ui-imports.ts [--write]
 */

import * as fs from 'fs';
import * as path from 'path';

const WRITE = process.argv.includes('--write');

const TARGET_DIRS = ['src/app', 'src/components', 'src/platform/ui/devtools'];

function collectFiles(dir: string): string[] {
  const results: string[] = [];
  if (!fs.existsSync(dir)) return results;
  for (const entry of fs.readdirSync(dir, { withFileTypes: true })) {
    const full = path.join(dir, entry.name);
    if (entry.isDirectory()) results.push(...collectFiles(full));
    else if (entry.name.endsWith('.tsx')) results.push(full);
  }
  return results;
}

function isUiComponentImport(name: string): boolean {
  return name.startsWith('Ui') && name !== 'UiIdentity';
}

function cleanupFile(content: string): string {
  let changed = false;

  const importRegex =
    /import\s+\{([\s\S]*?)\}\s+from\s+['"]@\/platform\/ui['"];?\n/g;

  let result = content.replace(importRegex, (match, imports: string) => {
    const specs = imports
      .split(',')
      .map((s) => s.trim())
      .filter(Boolean);
    const kept = specs.filter((s) => {
      const name = s.split(/\s+as\s+/)[0].trim();
      return !isUiComponentImport(name);
    });
    if (kept.length === specs.length) {
      return match;
    }
    changed = true;
    if (kept.length === 0) {
      return '';
    }
    return `import { ${kept.join(', ')} } from '@/platform/ui';\n`;
  });

  // Merge duplicate @/platform/ui imports
  const allSpecs: string[] = [];
  result = result.replace(importRegex, (_match, imports: string) => {
    allSpecs.push(...imports.split(',').map((s) => s.trim()).filter(Boolean));
    changed = true;
    return '';
  });
  const uniqueSpecs = [...new Set(allSpecs)];
  if (uniqueSpecs.length > 0) {
    const importLine = `import { ${uniqueSpecs.join(', ')} } from '@/platform/ui';\n`;
    const useClient = result.match(/^(['"])use client\1;?\r?\n/);
    if (useClient) {
      result = `'use client';\n${importLine}${result.replace(/^(['"])use client\1;?\r?\n/, '')}`;
    } else {
      result = importLine + result;
    }
  }

  // Ensure use client is first when present anywhere
  if (/^(['"])use client\1;?\r?\n/m.test(result) && !result.startsWith("'use client'") && !result.startsWith('"use client"')) {
    result = result.replace(/^(['"])use client\1;?\r?\n/m, '');
    result = `'use client';\n${result}`;
    changed = true;
  }

  result = result.replace(/\n{3,}/g, '\n\n');

  return changed ? result : content;
}

function main() {
  const root = process.cwd();
  const files = TARGET_DIRS.flatMap((d) => collectFiles(path.join(root, d)));
  let count = 0;

  for (const file of files) {
    const original = fs.readFileSync(file, 'utf-8');
    const cleaned = cleanupFile(original);
    if (cleaned !== original) {
      count += 1;
      if (WRITE) {
        fs.writeFileSync(file, cleaned, 'utf-8');
        console.log(`Γ£ô ${path.relative(root, file)}`);
      } else {
        console.log(`would clean: ${path.relative(root, file)}`);
      }
    }
  }

  console.log(`\n${count} file(s) ${WRITE ? 'cleaned' : 'would be cleaned'}.`);
}

main();

