 * Codemod: Ui* components ΓåÆ native elements with data-ui-uuid
 *
 * Usage: tsx scripts/codemod-ui-to-native.ts [--write]
 */

import * as fs from 'fs';
import * as path from 'path';
import * as ts from 'typescript';

const WRITE = process.argv.includes('--write');

const UI_COMPONENT_MAP: Record<string, string> = {
  UiDiv: 'div',
  UiSpan: 'span',
  UiLandmarkHeader: 'header',
  UiNav: 'nav',
  UiMain: 'main',
  UiSection: 'section',
  UiArticle: 'article',
  UiAside: 'aside',
  UiFooter: 'footer',
  UiH1: 'h1',
  UiH2: 'h2',
  UiH3: 'h3',
  UiH4: 'h4',
  UiH5: 'h5',
  UiH6: 'h6',
  UiP: 'p',
  UiStrong: 'strong',
  UiEm: 'em',
  UiA: 'a',
  UiImg: 'img',
  UiPicture: 'picture',
  UiFigure: 'figure',
  UiFigcaption: 'figcaption',
  UiVideo: 'video',
  UiAudio: 'audio',
  UiIframe: 'iframe',
  UiUl: 'ul',
  UiOl: 'ol',
  UiLi: 'li',
  UiTable: 'table',
  UiThead: 'thead',
  UiTbody: 'tbody',
  UiTr: 'tr',
  UiTh: 'th',
  UiTd: 'td',
  UiForm: 'form',
  UiOption: 'option',
  UiFieldset: 'fieldset',
  UiLegend: 'legend',
  UiDialog: 'dialog',
  UiDetails: 'details',
  UiSummary: 'summary',
  UiCanvas: 'canvas',
  UiSvg: 'svg',
  UiTemplate: 'template',
  UiSlot: 'slot',
  UiBr: 'br',
  UiHr: 'hr',
  UiCode: 'code',
  UiPre: 'pre',
  UiButton: 'button',
  UiInput: 'input',
  UiSelect: 'select',
  UiTextarea: 'textarea',
  UiCheckbox: 'input',
  UiRadio: 'input',
  UiSwitch: 'input',
  UiLabel: 'span',
  UiCard: 'div',
  UiModal: 'div',
  UiBadge: 'span',
  UiLink: 'Link',
  UiImage: 'Image',
};

const STRIP_PROPS = new Set(['ui', 'uiInstanceId', 'variant', 'size', 'level', 'asChild']);

const TARGET_DIRS = [
  'src/app',
  'src/components',
  'src/platform/ui/devtools',
];

function collectFiles(dir: string): string[] {
  const results: string[] = [];
  if (!fs.existsSync(dir)) return results;
  for (const entry of fs.readdirSync(dir, { withFileTypes: true })) {
    const full = path.join(dir, entry.name);
    if (entry.isDirectory()) {
      results.push(...collectFiles(full));
    } else if (entry.name.endsWith('.tsx')) {
      results.push(full);
    }
  }
  return results;
}

function getJsxTagName(name: ts.JsxTagNameExpression): string | null {
  if (ts.isIdentifier(name)) return name.text;
  return null;
}

function getAttr(
  attrs: ts.JsxAttributes,
  attrName: string
): ts.JsxAttribute | undefined {
  return attrs.properties.find(
    (p): p is ts.JsxAttribute =>
      ts.isJsxAttribute(p) &&
      ts.isIdentifier(p.name) &&
      p.name.text === attrName
  );
}

function getAttrExpression(attr: ts.JsxAttribute | undefined): ts.Expression | undefined {
  if (!attr?.initializer) return undefined;
  if (ts.isStringLiteral(attr.initializer)) {
    return attr.initializer;
  }
  if (ts.isJsxExpression(attr.initializer) && attr.initializer.expression) {
    return attr.initializer.expression;
  }
  return undefined;
}

function printNode(node: ts.Node, sourceFile: ts.SourceFile): string {
  const printer = ts.createPrinter({ removeComments: false });
  return printer.printNode(ts.EmitHint.Unspecified, node, sourceFile);
}

function resolveHeaderTag(attrs: ts.JsxAttributes): string {
  const levelAttr = getAttr(attrs, 'level');
  const expr = getAttrExpression(levelAttr);
  if (expr && ts.isNumericLiteral(expr)) {
    const level = parseInt(expr.text, 10);
    if (level >= 1 && level <= 6) return `h${level}`;
  }
  return 'h1';
}

function buildOpeningTag(
  tag: string,
  attrs: ts.JsxAttributes,
  sourceFile: ts.SourceFile,
  selfClosing: boolean
): string {
  const uiAttr = getAttr(attrs, 'ui');
  const uiExpr = getAttrExpression(uiAttr);
  const parts: string[] = [tag];

  if (uiExpr) {
    parts.push(`data-ui-uuid={${printNode(uiExpr, sourceFile)}.uuid}`);
  }

  const instanceAttr = getAttr(attrs, 'uiInstanceId');
  const instanceExpr = getAttrExpression(instanceAttr);
  if (instanceExpr) {
    parts.push(`data-ui-instance-id={${printNode(instanceExpr, sourceFile)}}`);
  }

  for (const prop of attrs.properties) {
    if (!ts.isJsxAttribute(prop) || !ts.isIdentifier(prop.name)) continue;
    const name = prop.name.text;
    if (STRIP_PROPS.has(name)) continue;
    parts.push(printNode(prop, sourceFile));
  }

  const attrStr = parts.slice(1).join(' ');
  if (selfClosing) {
    return attrStr ? `<${tag} ${attrStr} />` : `<${tag} />`;
  }
  return attrStr ? `<${tag} ${attrStr}>` : `<${tag}>`;
}

interface FileUsage {
  needsImage: boolean;
  needsLink: boolean;
  uiComponents: Set<string>;
}

function transformFile(filePath: string): { content: string; changed: boolean; usage: FileUsage } {
  const source = fs.readFileSync(filePath, 'utf-8');
  const sourceFile = ts.createSourceFile(filePath, source, ts.ScriptTarget.Latest, true, ts.ScriptKind.TSX);

  const usage: FileUsage = { needsImage: false, needsLink: false, uiComponents: new Set() };
  const replacements: Array<{ start: number; end: number; text: string }> = [];
  const headerTagStack: string[] = [];

  function visit(node: ts.Node) {
    if (ts.isJsxOpeningElement(node) || ts.isJsxSelfClosingElement(node)) {
      const tagName = getJsxTagName(node.tagName);
      if (tagName?.startsWith('Ui')) {
        usage.uiComponents.add(tagName);
        let nativeTag = UI_COMPONENT_MAP[tagName];
        if (tagName === 'UiHeader') {
          nativeTag = resolveHeaderTag(node.attributes);
          if (!ts.isJsxSelfClosingElement(node)) {
            headerTagStack.push(nativeTag);
          }
        }
        if (!nativeTag) {
          ts.forEachChild(node, visit);
          return;
        }
        if (nativeTag === 'Image') usage.needsImage = true;
        if (nativeTag === 'Link') usage.needsLink = true;

        const selfClosing = ts.isJsxSelfClosingElement(node);
        const text = buildOpeningTag(nativeTag, node.attributes, sourceFile, selfClosing);
        replacements.push({ start: node.getStart(sourceFile), end: node.getEnd(), text });
      }
    }

    if (ts.isJsxClosingElement(node)) {
      const tagName = getJsxTagName(node.tagName);
      if (tagName?.startsWith('Ui')) {
        let nativeTag = UI_COMPONENT_MAP[tagName];
        if (tagName === 'UiHeader') {
          nativeTag = headerTagStack.pop() || 'h1';
        }
        if (nativeTag === 'Image') nativeTag = 'Image';
        if (nativeTag === 'Link') nativeTag = 'Link';
        if (nativeTag) {
          replacements.push({
            start: node.getStart(sourceFile),
            end: node.getEnd(),
            text: `</${nativeTag}>`,
          });
        }
      }
    }

    ts.forEachChild(node, visit);
  }

  visit(sourceFile);

  if (replacements.length === 0) {
    return { content: source, changed: false, usage };
  }

  replacements.sort((a, b) => b.start - a.start);
  let content = source;
  for (const r of replacements) {
    content = content.slice(0, r.start) + r.text + content.slice(r.end);
  }

  content = cleanupImports(content, usage);
  return { content, changed: true, usage };
}

function cleanupImports(content: string, usage: FileUsage): string {
  const uiNames = [...usage.uiComponents];
  if (uiNames.length === 0) return content;

  const importRegex = /import\s+\{([^}]+)\}\s+from\s+['"]@\/platform\/ui['"];?\n/g;
  content = content.replace(importRegex, (_match, imports: string) => {
    const specs = imports
      .split(',')
      .map((s) => s.trim())
      .filter(Boolean);
    const kept = specs.filter((s) => {
      const name = s.split(/\s+as\s+/)[0].trim();
      return !name.startsWith('Ui') || name === 'UiIdentity';
    });
    if (kept.length === 0) return '';
    return `import { ${kept.join(', ')} } from '@/platform/ui';\n`;
  });

  // Merge duplicate @/platform/ui imports
  const uiImportLines: string[] = [];
  const otherLines: string[] = [];
  for (const line of content.split('\n')) {
    const m = line.match(/^import\s+\{([^}]+)\}\s+from\s+['"]@\/platform\/ui['"];?$/);
    if (m) {
      uiImportLines.push(...m[1].split(',').map((s) => s.trim()).filter(Boolean));
    } else {
      otherLines.push(line);
    }
  }

  const mergedUiImports = [...new Set(uiImportLines)];
  let result = otherLines.join('\n');

  const extraImports: string[] = [];
  if (usage.needsImage && !result.includes("from 'next/image'") && !result.includes('from "next/image"')) {
    extraImports.push("import Image from 'next/image';");
  }
  if (usage.needsLink && !result.includes("from 'next/link'") && !result.includes('from "next/link"')) {
    extraImports.push("import Link from 'next/link';");
  }

  const headerLines: string[] = [];
  if (extraImports.length) headerLines.push(...extraImports);
  if (mergedUiImports.length) {
    headerLines.push(`import { ${mergedUiImports.join(', ')} } from '@/platform/ui';`);
  }

  const useClientMatch = result.match(/^(['"]use client['"];?\n)/);
  if (useClientMatch) {
    result = useClientMatch[1] + headerLines.join('\n') + (headerLines.length ? '\n' : '') + result.slice(useClientMatch[1].length);
  } else {
    result = headerLines.join('\n') + (headerLines.length ? '\n\n' : '') + result;
  }

  return result;
}

function main() {
  const root = process.cwd();
  const files = TARGET_DIRS.flatMap((d) => collectFiles(path.join(root, d)));
  let changedCount = 0;

  for (const file of files) {
    const { content, changed } = transformFile(file);
    if (changed) {
      changedCount += 1;
      if (WRITE) {
        fs.writeFileSync(file, content, 'utf-8');
        console.log(`Γ£ô ${path.relative(root, file)}`);
      } else {
        console.log(`would change: ${path.relative(root, file)}`);
      }
    }
  }

  console.log(`\n${changedCount} file(s) ${WRITE ? 'updated' : 'would be updated'}.`);
  if (!WRITE) {
    console.log('Run with --write to apply changes.');
  }
}

main();

/**
 * Gova Project - Development Server Manager
 * Manages the Next.js dev server lifecycle with PID tracking and health checks.
 * Compatible with: Next.js 16.2.9, Node.js, Windows (PowerShell/CMD)
 */

import { spawn, execSync } from 'child_process';
import fs from 'fs';
import path from 'path';
import http from 'http';

// ΓöÇΓöÇΓöÇ Constants ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
const ROOT_DIR = process.cwd();
const PID_FILE = path.join(ROOT_DIR, '.server.pid');
const LOG_FILE = path.join(ROOT_DIR, 'logs', 'dev-server.log');
const NEXT_PORT = parseInt(process.env.PORT ?? '3001', 10);
const NEXT_HOST = process.env.HOSTNAME ?? 'localhost';
const HEALTH_CHECK_TIMEOUT_MS = 30_000;
const HEALTH_CHECK_INTERVAL_MS = 1_000;

// ΓöÇΓöÇΓöÇ Utilities ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
function ensureLogsDir(): void {
  const logsDir = path.join(ROOT_DIR, 'logs');
  if (!fs.existsSync(logsDir)) {
    fs.mkdirSync(logsDir, { recursive: true });
  }
}

function log(message: string): void {
  const timestamp = new Date().toISOString();
  const line = `[${timestamp}] ${message}`;
  console.log(line);

  try {
    ensureLogsDir();
    fs.appendFileSync(LOG_FILE, line + '\n', 'utf-8');
  } catch {
    // Non-critical: log file write failure should not block execution
  }
}

function logError(message: string, error?: unknown): void {
  const detail = error instanceof Error ? error.message : String(error ?? '');
  const line = detail ? `${message}: ${detail}` : message;
  console.error(`[ERROR] ${line}`);

  try {
    ensureLogsDir();
    fs.appendFileSync(LOG_FILE, `[ERROR] ${new Date().toISOString()} ${line}\n`, 'utf-8');
  } catch {
    // Non-critical
  }
}

// ΓöÇΓöÇΓöÇ PID Management ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
function getServerPid(): number | null {
  if (!fs.existsSync(PID_FILE)) return null;

  try {
    const raw = fs.readFileSync(PID_FILE, 'utf-8').trim();
    const pid = parseInt(raw, 10);
    if (isNaN(pid)) {
      fs.unlinkSync(PID_FILE);
      return null;
    }

    // Verify the process is actually running
    process.kill(pid, 0);
    return pid;
  } catch {
    // Process is not running ΓÇö clean up stale PID file
    try { fs.unlinkSync(PID_FILE); } catch { /* ignore */ }
    return null;
  }
}

function savePid(pid: number): void {
  try {
    fs.writeFileSync(PID_FILE, pid.toString(), 'utf-8');
  } catch (error) {
    logError('Failed to write PID file', error);
  }
}

function removePid(): void {
  try {
    if (fs.existsSync(PID_FILE)) fs.unlinkSync(PID_FILE);
  } catch {
    // Non-critical
  }
}

// ΓöÇΓöÇΓöÇ Health Check ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
function waitForServer(): Promise<boolean> {
  return new Promise((resolve) => {
    const start = Date.now();

    const check = () => {
      const elapsed = Date.now() - start;
      if (elapsed >= HEALTH_CHECK_TIMEOUT_MS) {
        logError(`Server did not become ready within ${HEALTH_CHECK_TIMEOUT_MS / 1000}s`);
        resolve(false);
        return;
      }

      const req = http.request(
        { host: NEXT_HOST, port: NEXT_PORT, path: '/', method: 'GET', timeout: 2000 },
        (res) => {
          if (res.statusCode !== undefined && res.statusCode < 500) {
            log(`Server is ready at http://${NEXT_HOST}:${NEXT_PORT} (${elapsed}ms)`);
            resolve(true);
          } else {
            setTimeout(check, HEALTH_CHECK_INTERVAL_MS);
          }
        }
      );

      req.on('error', () => setTimeout(check, HEALTH_CHECK_INTERVAL_MS));
      req.on('timeout', () => {
        req.destroy();
        setTimeout(check, HEALTH_CHECK_INTERVAL_MS);
      });
      req.end();
    };

    check();
  });
}

// ΓöÇΓöÇΓöÇ Server Lifecycle ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
function startServer(): void {
  const existingPid = getServerPid();
  if (existingPid) {
    log(`Server is already running (PID: ${existingPid}) ΓåÆ http://${NEXT_HOST}:${NEXT_PORT}`);
    return;
  }

  log('Starting Gova development server...');

  ensureLogsDir();
  const logStream = fs.openSync(LOG_FILE, 'a');

  const server = spawn(
    'node',
    ['node_modules/.bin/next', 'dev', '--port', String(NEXT_PORT), '--hostname', NEXT_HOST],
    {
      cwd: ROOT_DIR,
      detached: true,
      stdio: ['ignore', logStream, logStream],
      env: {
        ...process.env,
        NODE_ENV: 'development',
        PORT: String(NEXT_PORT),
        HOSTNAME: NEXT_HOST,
      },
    }
  );

  if (!server.pid) {
    logError('Failed to spawn server process');
    process.exit(1);
  }

  savePid(server.pid);
  server.unref();

  server.on('error', (error) => {
    logError('Server process error', error);
    removePid();
  });

  log(`Server process spawned (PID: ${server.pid})`);
  log('Waiting for server to become ready...');

  waitForServer().then((ready) => {
    if (ready) {
      log('Γ£ô Gova dev server is up and running');
    } else {
      logError('Server may have failed to start ΓÇö check logs/dev-server.log');
    }
  }).catch((err) => logError('Health check failed', err));
}

function stopServer(): void {
  const pid = getServerPid();
  if (!pid) {
    log('Server is not running');
    return;
  }

  log(`Stopping server (PID: ${pid})...`);

  try {
    if (process.platform === 'win32') {
      // On Windows, kill the process tree to avoid orphaned Next.js workers
      execSync(`taskkill /PID ${pid} /T /F`, { stdio: 'pipe' });
    } else {
      process.kill(-pid, 'SIGTERM');
    }
    removePid();
    log('Γ£ô Server stopped successfully');
  } catch (error) {
    logError('Failed to stop server gracefully ΓÇö forcing kill', error);
    try {
      if (process.platform === 'win32') {
        execSync(`taskkill /PID ${pid} /F`, { stdio: 'pipe' });
      } else {
        process.kill(pid, 'SIGKILL');
      }
      removePid();
      log('Γ£ô Server force-killed');
    } catch (killError) {
      logError('Force kill also failed', killError);
    }
  }
}

function restartServer(): void {
  log('Restarting Gova development server...');
  stopServer();
  setTimeout(() => startServer(), 1500);
}

function clearCache(): void {
  const pid = getServerPid();
  if (pid) {
    log('Stopping server before clearing cache...');
    stopServer();
    // Wait for process to fully stop before deleting cache
    setTimeout(() => performCacheClear(), 2000);
  } else {
    performCacheClear();
  }
}

function performCacheClear(): void {
  const targets = [
    path.join(ROOT_DIR, '.next'),
    path.join(ROOT_DIR, '.swc'),
    path.join(ROOT_DIR, 'tsconfig.tsbuildinfo'),
  ];

  let cleared = false;
  for (const target of targets) {
    if (fs.existsSync(target)) {
      try {
        fs.rmSync(target, { recursive: true, force: true });
        log(`Γ£ô Cleared: ${path.basename(target)}`);
        cleared = true;
      } catch (error) {
        logError(`Failed to clear ${target}`, error);
      }
    }
  }

  if (!cleared) {
    log('No cache to clear');
  } else {
    log('Γ£ô Cache cleared successfully ΓÇö run "dev" to rebuild');
  }
}

function showStatus(): void {
  const pid = getServerPid();

  if (pid) {
    log(`Status: RUNNING (PID: ${pid})`);
    log(`URL:    http://${NEXT_HOST}:${NEXT_PORT}`);
    log(`Logs:   ${LOG_FILE}`);
  } else {
    log('Status: STOPPED');
    log(`Run "npm run server:start" to start the development server`);
  }
}

function showLogs(): void {
  if (!fs.existsSync(LOG_FILE)) {
    log('No log file found ΓÇö server has not been started yet');
    return;
  }

  try {
    const content = fs.readFileSync(LOG_FILE, 'utf-8');
    // Show last 50 lines
    const lines = content.split('\n').filter(Boolean);
    const tail = lines.slice(-50).join('\n');
    console.log('\n=== Gova Dev Server Logs (last 50 lines) ===\n');
    console.log(tail);
    console.log('\n===========================================');
  } catch (error) {
    logError('Failed to read log file', error);
  }
}

// ΓöÇΓöÇΓöÇ CLI Dispatch ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
const command = process.argv[2];

switch (command) {
  case 'start':
    startServer();
    break;
  case 'stop':
    stopServer();
    break;
  case 'restart':
    restartServer();
    break;
  case 'clear-cache':
    clearCache();
    break;
  case 'status':
    showStatus();
    break;
  case 'logs':
    showLogs();
    break;
  default:
    console.log(`
Gova Development Server Manager
ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
Usage: npm run server <command>

Commands:
  start        Start the development server (detached, with health check)
  stop         Stop the running server (Windows process tree kill)
  restart      Stop + start the server
  clear-cache  Clear .next, .swc, and tsbuildinfo caches
  status       Show server status (PID + URL)
  logs         Tail the last 50 lines of the server log

Server URL:  http://${NEXT_HOST}:${NEXT_PORT}
Log file:    ${LOG_FILE}
`);
}

