  }
  
  // Step 3: Validate with ESLint
  console.log(`\n≡ƒöì Step 3: Validating with ESLint...`);
  try {
    const eslintCmd = `cd "${process.cwd()}" && npx eslint "src/features/${feature}/**/*.{ts,tsx}"`;
