#!/usr/bin/env tsx
import { existsSync, mkdirSync, readdirSync, readFileSync, writeFileSync } from 'fs';
import { dirname, join } from 'path';

const ROOT = process.cwd();
const REGISTRY_DIRS = [
  join(ROOT, 'src', 'platform', 'ui', 'registry', 'features'),
  join(ROOT, 'src', 'platform', 'ui', 'registry', 'categories'),
];
const MANIFEST_PATH = join(ROOT, 'src', 'platform', 'ui', 'registry', 'uuid-manifest.json');
const UI_UUID_NAMESPACE = 'gova.ui-registry';
const VALID_LIFECYCLES = ['active', 'deprecated', 'removed'] as const;

type Lifecycle = (typeof VALID_LIFECYCLES)[number];

interface ManifestIdentity {
  uuid: string;
  id: string;
  path: string;
  feature: string;
  lifecycle: Lifecycle;
  previousIds: string[];
  previousPaths: string[];
  aliases: string[];
}

interface Manifest {
  version: 1;
  namespace: string;
  generatedAt: string;
  identities: Record<string, ManifestIdentity>;
  removedIdentities: Record<string, ManifestIdentity>;
}

function fnv1a32(input: string, seed: number): number {
  let hash = 0x811c9dc5 ^ seed;
  for (let i = 0; i < input.length; i++) {
    hash ^= input.charCodeAt(i);
    hash = Math.imul(hash, 0x01000193);
  }
  return hash >>> 0;
}

function toHex32(value: number): string {
  return value.toString(16).padStart(8, '0');
}

function createDeterministicUiUuid(seed: string): string {
  const source = `${UI_UUID_NAMESPACE}:${seed}`;
  const hex = [
    toHex32(fnv1a32(source, 0)),
    toHex32(fnv1a32(source, 1)),
    toHex32(fnv1a32(source, 2)),
    toHex32(fnv1a32(source, 3)),
  ].join('');

  return [
    hex.slice(0, 8),
    hex.slice(8, 12),
    `5${hex.slice(13, 16)}`,
    `${((parseInt(hex.slice(16, 17), 16) & 0x3) | 0x8).toString(16)}${hex.slice(17, 20)}`,
    hex.slice(20, 32),
  ].join('-');
}

function listTsFiles(dir: string): string[] {
  const files: string[] = [];
  for (const item of readdirSync(dir, { withFileTypes: true })) {
    const fullPath = join(dir, item.name);
    if (item.isDirectory()) {
      files.push(...listTsFiles(fullPath));
    } else if (item.isFile() && item.name.endsWith('.ts')) {
      files.push(fullPath);
    }
  }
  return files;
}

function normalizeManifestIdentity(identity: ManifestIdentity): ManifestIdentity {
  return {
    uuid: identity.uuid,
    id: identity.id,
    path: identity.path,
    feature: identity.feature,
    lifecycle: VALID_LIFECYCLES.includes(identity.lifecycle) ? identity.lifecycle : 'active',
    previousIds: identity.previousIds ?? [],
    previousPaths: identity.previousPaths ?? [],
    aliases: identity.aliases ?? [],
  };
}

function readManifest(): Manifest | null {
  if (!existsSync(MANIFEST_PATH)) return null;
  const manifest = JSON.parse(readFileSync(MANIFEST_PATH, 'utf-8')) as Partial<Manifest>;
  return {
    version: 1,
    namespace: manifest.namespace ?? UI_UUID_NAMESPACE,
    generatedAt: manifest.generatedAt ?? new Date().toISOString(),
    identities: Object.fromEntries(
      Object.entries(manifest.identities ?? {}).map(([uuid, identity]) => [
        uuid,
        normalizeManifestIdentity({ ...(identity as ManifestIdentity), uuid }),
      ])
    ),
    removedIdentities: Object.fromEntries(
      Object.entries(manifest.removedIdentities ?? {}).map(([uuid, identity]) => [
        uuid,
        normalizeManifestIdentity({
          ...(identity as ManifestIdentity),
          uuid,
          lifecycle: 'removed',
        }),
      ])
    ),
  };
}

function findManifestUuid(manifest: Manifest | null, id: string, path: string): string {
  if (!manifest) return createDeterministicUiUuid(id);

  const entries = [
    ...Object.values(manifest.identities),
    ...Object.values(manifest.removedIdentities),
  ];
  const byIdOrHistory = entries.find(
    (entry) =>
      entry.id === id ||
      entry.path === path ||
      entry.previousIds.includes(id) ||
      entry.previousPaths.includes(path) ||
      entry.aliases.includes(id) ||
      entry.aliases.includes(path)
  );

  return byIdOrHistory?.uuid ?? createDeterministicUiUuid(id);
}

function extractString(body: string, key: string): string {
  const match = body.match(new RegExp(`(?:^|\\n)\\s*${key}:\\s*'([^']+)'`));
  return match?.[1] ?? '';
}

function extractStringArray(body: string, key: string): string[] {
  const match = body.match(new RegExp(`(?:^|\\n)\\s*${key}:\\s*\\[([^\\]]*)\\]`));
  if (!match?.[1]) return [];
  return Array.from(match[1].matchAll(/'([^']+)'/g)).map((item) => item[1]);
}

function extractLifecycle(body: string): Lifecycle {
  const lifecycle = extractString(body, 'lifecycle') as Lifecycle;
  if (VALID_LIFECYCLES.includes(lifecycle)) return lifecycle;
  return /\bdeprecated:\s*true\b/.test(body) ? 'deprecated' : 'active';
}

function materializeIdentityBlock(
  fullMatch: string,
  indent: string,
  body: string,
  manifest: Manifest | null,
  identities: ManifestIdentity[]
): string {
  const id = extractString(body, 'id');
  const path = extractString(body, 'path');
  const feature = extractString(body, 'feature');
  if (!id || !path) return fullMatch;

  const previousIds = extractStringArray(body, 'previousIds');
  const previousPaths = extractStringArray(body, 'previousPaths');
  const aliases = extractStringArray(body, 'aliases');
  const existingUuid = extractString(body, 'uuid');
  const uuid = existingUuid || findManifestUuid(manifest, id, path);
  const lifecycle = extractLifecycle(body);

  identities.push({ uuid, id, path, feature, lifecycle, previousIds, previousPaths, aliases });

  let nextBody = body;
  if (!existingUuid) {
    nextBody = `${indent}uuid: '${uuid}',\n${nextBody}`;
  }
  if (!extractString(nextBody, 'lifecycle')) {
    nextBody = nextBody.replace(
      new RegExp(`(${indent}path:\\s*'[^']+',\\r?\\n)`),
      `$1${indent}lifecycle: '${lifecycle}',\n`
    );
  }

  return `{\n${nextBody}\n${indent.slice(0, -2)}} as const`;
}

function materializeFile(filePath: string, manifest: Manifest | null): ManifestIdentity[] {
  const originalContent = readFileSync(filePath, 'utf-8');
  let content = originalContent;
  const identities: ManifestIdentity[] = [];

  content = content.replace(
    /{\r?\n(\s*)([^{}]*?\bid:\s*'[^']+'[^{}]*?\bpath:\s*'[^']+'[^{}]*?)\r?\n\s*}\s+as const/g,
    (fullMatch, indent: string, body: string) =>
      materializeIdentityBlock(fullMatch, indent, body, manifest, identities)
  );

  if (content !== originalContent) {
    writeFileSync(filePath, content, 'utf-8');
  }
  return identities;
}

function writeManifest(identities: ManifestIdentity[], previousManifest: Manifest | null) {
  const unique = [
    ...new Map(identities.map((identity) => [identity.uuid, identity])).values(),
  ].sort((a, b) => a.id.localeCompare(b.id));
  const activeUuidSet = new Set(unique.map((identity) => identity.uuid));
  const previouslyRemoved = Object.values(previousManifest?.removedIdentities ?? {});
  const newlyRemoved = Object.values(previousManifest?.identities ?? {})
    .filter((identity) => !activeUuidSet.has(identity.uuid))
    .map((identity) => ({ ...identity, lifecycle: 'removed' as const }));
  const removedIdentities = Object.fromEntries(
    [...previouslyRemoved, ...newlyRemoved]
      .filter((identity) => !activeUuidSet.has(identity.uuid))
      .sort((a, b) => a.id.localeCompare(b.id))
      .map((identity) => [identity.uuid, identity])
  );

  const manifest: Manifest = {
    version: 1,
    namespace: UI_UUID_NAMESPACE,
    generatedAt: new Date().toISOString(),
    identities: Object.fromEntries(unique.map((identity) => [identity.uuid, identity])),
    removedIdentities,
  };

  mkdirSync(dirname(MANIFEST_PATH), { recursive: true });
  writeFileSync(MANIFEST_PATH, `${JSON.stringify(manifest, null, 2)}\n`, 'utf-8');
}

function main() {
  const previousManifest = readManifest();
  const allIdentities = REGISTRY_DIRS.flatMap((dir) => listTsFiles(dir)).flatMap((file) =>
    materializeFile(file, previousManifest)
  );

  writeManifest(allIdentities, previousManifest);
  console.log(`Materialized ${allIdentities.length} UI UUIDs.`);
  console.log(`Manifest: ${MANIFEST_PATH}`);
}

main();

#!/usr/bin/env tsx
import { execFileSync } from 'child_process';
import { readdirSync, readFileSync, writeFileSync } from 'fs';
import { join } from 'path';

const ROOT = process.cwd();
const REGISTRY_DIRS = [
  join(ROOT, 'src', 'platform', 'ui', 'registry', 'features'),
  join(ROOT, 'src', 'platform', 'ui', 'registry', 'categories'),
];

interface MoveOptions {
  lookup: string;
  id?: string;
  path?: string;
  feature?: string;
}

function listTsFiles(dir: string): string[] {
  return readdirSync(dir, { withFileTypes: true }).flatMap((item) => {
    const fullPath = join(dir, item.name);
    if (item.isDirectory()) return listTsFiles(fullPath);
    if (item.isFile() && item.name.endsWith('.ts')) return [fullPath];
    return [];
  });
}

function parseArgs(): MoveOptions {
  const [, , lookup, ...rest] = process.argv;
  if (!lookup) {
    throw new Error(
      'Usage: npx tsx scripts/registry-move-identity.ts <uuid|id|path> --id NEW_ID --path new.path --feature feature'
    );
  }

  const options: MoveOptions = { lookup };
  for (let i = 0; i < rest.length; i += 2) {
    const key = rest[i];
    const value = rest[i + 1];
    if (!value) throw new Error(`Missing value for ${key}`);
    if (key === '--id') options.id = value;
    else if (key === '--path') options.path = value;
    else if (key === '--feature') options.feature = value;
    else throw new Error(`Unknown option: ${key}`);
  }

  if (!options.id && !options.path && !options.feature) {
    throw new Error('Provide at least one of --id, --path, or --feature.');
  }

  return options;
}

function extractString(body: string, key: string): string {
  const match = body.match(new RegExp(`${key}:\\s*'([^']+)'`));
  return match?.[1] ?? '';
}

function hasArrayValue(body: string, key: string, value: string): boolean {
  const match = body.match(new RegExp(`${key}:\\s*\\[([^\\]]*)\\]`));
  return Boolean(match?.[1]?.includes(`'${value}'`));
}

function addArrayValue(body: string, key: string, value: string, indent: string): string {
  if (!value || hasArrayValue(body, key, value)) return body;

  const arrayRegex = new RegExp(`${key}:\\s*\\[([^\\]]*)\\],?`);
  if (arrayRegex.test(body)) {
    return body.replace(arrayRegex, (_match, values: string) => {
      const trimmed = values.trim();
      const nextValues = trimmed ? `${trimmed}, '${value}'` : `'${value}'`;
      return `${key}: [${nextValues}],`;
    });
  }

  const updatedAtRegex = new RegExp(`(\\n${indent}updatedAt:\\s*'[^']+',)`);
  return body.replace(updatedAtRegex, `$1\n${indent}${key}: ['${value}'] as const,`);
}

function updateString(body: string, key: string, value: string): string {
  return body.replace(new RegExp(`${key}:\\s*'[^']+'`), `${key}: '${value}'`);
}

function updateIdentityInFile(filePath: string, options: MoveOptions): boolean {
  const content = readFileSync(filePath, 'utf-8');
  let changed = false;

  const nextContent = content.replace(
    /{\r?\n(\s*)uuid:\s*'([^']+)',\r?\n([\s\S]*?)\r?\n\s*}\s+as const/g,
    (fullMatch, indent: string, uuid: string, rest: string) => {
      const currentId = extractString(rest, 'id');
      const currentPath = extractString(rest, 'path');
      const matches = [uuid, currentId, currentPath].includes(options.lookup);
      if (!matches) return fullMatch;

      let nextRest = rest;
      if (options.id && options.id !== currentId) {
        nextRest = addArrayValue(nextRest, 'previousIds', currentId, indent);
        nextRest = updateString(nextRest, 'id', options.id);
      }
      if (options.path && options.path !== currentPath) {
        nextRest = addArrayValue(nextRest, 'previousPaths', currentPath, indent);
        nextRest = updateString(nextRest, 'path', options.path);
      }
      if (options.feature) {
        nextRest = updateString(nextRest, 'feature', options.feature);
      }

      changed = true;
      return `{\n${indent}uuid: '${uuid}',\n${nextRest}\n${indent.slice(0, -2)}} as const`;
    }
  );

  if (changed) {
    writeFileSync(filePath, nextContent, 'utf-8');
  }

  return changed;
}

function main() {
  const options = parseArgs();
  const changedFiles = REGISTRY_DIRS.flatMap((dir) => listTsFiles(dir)).filter((file) =>
    updateIdentityInFile(file, options)
  );

  if (changedFiles.length === 0) {
    throw new Error(`No UI identity matched "${options.lookup}".`);
  }

  execFileSync('cmd', ['/c', 'npx', 'tsx', 'scripts/registry-materialize-uuids.ts'], {
    stdio: 'inherit',
    cwd: ROOT,
  });

  console.log(`Updated ${changedFiles.length} registry file(s).`);
}

main();

#!/usr/bin/env tsx
import { execFileSync } from 'child_process';
import { readdirSync, readFileSync, writeFileSync } from 'fs';
import { join } from 'path';

const ROOT = process.cwd();
const REGISTRY_DIRS = [
  join(ROOT, 'src', 'platform', 'ui', 'registry', 'features'),
  join(ROOT, 'src', 'platform', 'ui', 'registry', 'categories'),
];

function listTsFiles(dir: string): string[] {
  return readdirSync(dir, { withFileTypes: true }).flatMap((item) => {
    const fullPath = join(dir, item.name);
    if (item.isDirectory()) return listTsFiles(fullPath);
    if (item.isFile() && item.name.endsWith('.ts')) return [fullPath];
    return [];
  });
}

function extractString(body: string, key: string): string {
  const match = body.match(new RegExp(`(?:^|\\n)\\s*${key}:\\s*'([^']+)'`));
  return match?.[1] ?? '';
}

function removeIdentityFromFile(filePath: string, lookup: string): boolean {
  const content = readFileSync(filePath, 'utf-8');
  let removed = false;

  const nextContent = content.replace(
    /\n\s*[A-Z0-9_]+:\s*{\r?\n(\s*)([\s\S]*?\buuid:\s*'[^']+'[\s\S]*?\bid:\s*'[^']+'[\s\S]*?\bpath:\s*'[^']+'[\s\S]*?)\r?\n\s*}\s+as const,?/g,
    (fullMatch, _indent: string, body: string) => {
      const uuid = extractString(body, 'uuid');
      const id = extractString(body, 'id');
      const path = extractString(body, 'path');
      if (![uuid, id, path].includes(lookup)) return fullMatch;

      removed = true;
      return '';
    }
  );

  if (removed) {
    writeFileSync(filePath, nextContent, 'utf-8');
  }

  return removed;
}

function main() {
  const lookup = process.argv[2];
  if (!lookup) {
    throw new Error('Usage: npm run registry:remove -- <uuid|id|path>');
  }

  const changedFiles = REGISTRY_DIRS.flatMap((dir) => listTsFiles(dir)).filter((file) =>
    removeIdentityFromFile(file, lookup)
  );

  if (changedFiles.length === 0) {
    throw new Error(`No UI identity matched "${lookup}".`);
  }

  execFileSync('cmd', ['/c', 'npx', 'tsx', 'scripts/registry-materialize-uuids.ts'], {
    stdio: 'inherit',
    cwd: ROOT,
  });

  console.log(`Removed ${lookup} from active registry and preserved it in removedIdentities.`);
}

main();

#!/usr/bin/env tsx
import { execFileSync } from 'child_process';

import {
  ALL_UI_IDENTITIES,
  getDuplicateUiAliases,
  getDuplicateUiUuids,
  getUiIdentityLifecycle,
  getUiIdentityUuid,
  isValidUiUuid,
} from '../src/platform/ui/registry/registry';
import UUID_MANIFEST from '../src/platform/ui/registry/uuid-manifest.json';

type Lifecycle = 'active' | 'deprecated' | 'removed';

interface ManifestIdentity {
  uuid: string;
  id: string;
  path: string;
  feature: string;
  lifecycle?: Lifecycle;
  previousIds?: string[];
  previousPaths?: string[];
  aliases?: string[];
}

interface Manifest {
  identities: Record<string, ManifestIdentity>;
  removedIdentities?: Record<string, ManifestIdentity>;
}

const manifest = UUID_MANIFEST as Manifest;
const manifestIdentities = manifest.identities;
const removedManifestIdentities = manifest.removedIdentities ?? {};
const errors: string[] = [];

function identityKeys(identity: ManifestIdentity): string[] {
  return [
    identity.id,
    identity.path,
    ...(identity.previousIds ?? []),
    ...(identity.previousPaths ?? []),
    ...(identity.aliases ?? []),
  ].filter(Boolean);
}

function readHeadManifest(): Manifest | null {
  try {
    const raw = execFileSync('git', ['show', 'HEAD:src/platform/ui/registry/uuid-manifest.json'], {
      encoding: 'utf-8',
      stdio: ['ignore', 'pipe', 'ignore'],
    });
    return JSON.parse(raw) as Manifest;
  } catch {
    return null;
  }
}

const missingUuid = ALL_UI_IDENTITIES.filter((identity) => !identity.uuid);
if (missingUuid.length > 0) {
  errors.push(`Missing uuid: ${missingUuid.map((identity) => identity.id).join(', ')}`);
}

const invalidUuid = ALL_UI_IDENTITIES.filter((identity) => !isValidUiUuid(identity.uuid));
if (invalidUuid.length > 0) {
  errors.push(
    `Invalid uuid: ${invalidUuid.map((identity) => `${identity.id}:${identity.uuid}`).join(', ')}`
  );
}

const duplicateUuids = getDuplicateUiUuids();
if (duplicateUuids.length > 0) {
  errors.push(`Duplicate uuid: ${duplicateUuids.join(', ')}`);
}

const duplicateAliases = getDuplicateUiAliases();
if (duplicateAliases.length > 0) {
  errors.push(`Duplicate/conflicting aliases: ${duplicateAliases.join(', ')}`);
}

const invalidLifecycle = ALL_UI_IDENTITIES.filter(
  (identity) => !['active', 'deprecated', 'removed'].includes(getUiIdentityLifecycle(identity))
);
if (invalidLifecycle.length > 0) {
  errors.push(
    `Invalid lifecycle: ${invalidLifecycle.map((identity) => `${identity.id}:${String(identity.lifecycle)}`).join(', ')}`
  );
}

const missingManifest = ALL_UI_IDENTITIES.filter(
  (identity) => !manifestIdentities[getUiIdentityUuid(identity)]
);
if (missingManifest.length > 0) {
  errors.push(
    `Missing manifest entries: ${missingManifest.map((identity) => identity.id).join(', ')}`
  );
}

const reusedRemoved = ALL_UI_IDENTITIES.filter(
  (identity) => removedManifestIdentities[getUiIdentityUuid(identity)]
);
if (reusedRemoved.length > 0) {
  errors.push(
    `Removed uuid reused in active registry: ${reusedRemoved.map((identity) => `${identity.id}:${identity.uuid}`).join(', ')}`
  );
}

const mismatches = ALL_UI_IDENTITIES.flatMap((identity) => {
  const entry = manifestIdentities[getUiIdentityUuid(identity)];
  if (!entry) return [];

  const identityErrors: string[] = [];
  if (entry.id !== identity.id) identityErrors.push(`${identity.uuid} id mismatch`);
  if (entry.path !== identity.path) identityErrors.push(`${identity.uuid} path mismatch`);
  if (entry.feature !== identity.feature) identityErrors.push(`${identity.uuid} feature mismatch`);
  if ((entry.lifecycle ?? 'active') !== getUiIdentityLifecycle(identity)) {
    identityErrors.push(`${identity.uuid} lifecycle mismatch`);
  }
  return identityErrors;
});

if (mismatches.length > 0) {
  errors.push(`Manifest mismatches: ${mismatches.join(', ')}`);
}

const currentByHistoricalKey = new Map<string, ManifestIdentity>();
Object.values(manifestIdentities).forEach((identity) => {
  identityKeys(identity).forEach((key) => currentByHistoricalKey.set(key, identity));
});

const headManifest = readHeadManifest();
if (headManifest) {
  Object.values(headManifest.identities ?? {}).forEach((headIdentity) => {
    const current = identityKeys(headIdentity)
      .map((key) => currentByHistoricalKey.get(key))
      .find(Boolean);

    if (current && current.uuid !== headIdentity.uuid) {
      errors.push(
        `UUID changed for historical identity "${headIdentity.id}" / "${headIdentity.path}": ` +
          `${headIdentity.uuid} -> ${current.uuid}. Use registry:move or registry:add instead.`
      );
    }
  });
}

if (errors.length > 0) {
  console.error('[UI Registry UUID Validation] FAILED');
  errors.forEach((error) => console.error(`- ${error}`));
  process.exit(1);
}

console.log(
  JSON.stringify(
    {
      status: 'ok',
      total: ALL_UI_IDENTITIES.length,
      manifestEntries: Object.keys(manifestIdentities).length,
      removedManifestEntries: Object.keys(removedManifestIdentities).length,
    },
    null,
    2
  )
);

import { readFileSync, readdirSync, existsSync } from 'fs';
import { join } from 'path';

interface LegacyViolation {
  id: string;
  type: 'hardcoded_text' | 'missing_ui_identifier' | 'missing_translation' | 'missing_binding';
  severity: 'CRITICAL' | 'HIGH' | 'MEDIUM' | 'LOW';
  file: string;
  line: number;
  column: number;
  feature: string;
  description: string;
  suggestion: string;
  autoFixable: boolean;
}

interface LegacyViolationReport {
  scanDate: string;
  totalViolations: number;
  byType: Record<string, number>;
  bySeverity: Record<string, number>;
  byFeature: Record<string, number>;
  violations: LegacyViolation[];
}

function scanLegacyViolations(): LegacyViolationReport {
  console.log('≡ƒöì Starting Legacy Violation Scan...\n');
  
  const violations: LegacyViolation[] = [];
  const srcPath = join(process.cwd(), 'src');
  
  // Scan all TypeScript and TSX files
  scanDirectory(srcPath, violations);
  
  // Group violations
  const byType: Record<string, number> = {};
  const bySeverity: Record<string, number> = {};
  const byFeature: Record<string, number> = {};
  
  for (const violation of violations) {
    byType[violation.type] = (byType[violation.type] || 0) + 1;
    bySeverity[violation.severity] = (bySeverity[violation.severity] || 0) + 1;
    byFeature[violation.feature] = (byFeature[violation.feature] || 0) + 1;
  }
  
  const report: LegacyViolationReport = {
    scanDate: new Date().toISOString(),
    totalViolations: violations.length,
    byType,
    bySeverity,
    byFeature,
    violations,
  };
  
  console.log(`\n≡ƒôè Scan Complete:`);
  console.log(`   Total Violations: ${violations.length}`);
  console.log(`   By Type: ${JSON.stringify(byType, null, 2)}`);
  console.log(`   By Severity: ${JSON.stringify(bySeverity, null, 2)}`);
  console.log(`   By Feature: ${JSON.stringify(byFeature, null, 2)}`);
  
  return report;
}

function scanDirectory(dirPath: string, violations: LegacyViolation[]): void {
  if (!existsSync(dirPath)) {
    return;
  }
  
  const items = readdirSync(dirPath, { withFileTypes: true });
  
  for (const item of items) {
    const fullPath = join(dirPath, item.name);
    
    if (item.isDirectory()) {
      // Skip node_modules and other common exclusions
      if (item.name === 'node_modules' || item.name === '.next' || item.name === 'build') {
        continue;
      }
      scanDirectory(fullPath, violations);
    } else if (item.name.endsWith('.tsx') || item.name.endsWith('.ts')) {
      scanFile(fullPath, violations);
    }
  }
}

function scanFile(filePath: string, violations: LegacyViolation[]): void {
  try {
    const content = readFileSync(filePath, 'utf-8');
    const lines = content.split('\n');
    
    // Extract feature from file path
    const feature = extractFeatureFromPath(filePath);
    
    // Scan for hardcoded text in JSX
    scanForHardcodedText(filePath, lines, feature, violations);
    
    // Scan for missing UI identifiers (native HTML elements)
    scanForMissingUiIdentifiers(filePath, lines, feature, violations);
    
    // Scan for missing translation usage
    scanForMissingTranslations(filePath, lines, feature, violations);
    
    // Scan for UI identifiers without binding
    scanForMissingBindings(filePath, lines, feature, violations);
  } catch (error) {
    console.error(`Error scanning ${filePath}:`, error);
  }
}

function extractFeatureFromPath(filePath: string): string {
  const parts = filePath.split(/[/\\]/);
  const featuresIndex = parts.indexOf('features');
  
  if (featuresIndex !== -1 && featuresIndex + 1 < parts.length) {
    return parts[featuresIndex + 1];
  }
  
  // Default to 'common' if not in features folder
  return 'common';
}

function scanForHardcodedText(
  filePath: string,
  lines: string[],
  feature: string,
  violations: LegacyViolation[]
): void {
  for (let i = 0; i < lines.length; i++) {
    const line = lines[i];
    const lineNum = i + 1;
    
    // Look for JSX text content that's not in expressions
    // Pattern: >Text< where Text is not a number or single character
    const jsxTextPattern = />\s*([A-Z][^<{]+)\s*</g;
    let match;
    
    while ((match = jsxTextPattern.exec(line)) !== null) {
      const text = match[1].trim();
      
      // Skip if it's too short or looks like code
      if (text.length < 2 || /^[A-Z_\-0-9]+$/.test(text)) {
        continue;
      }
      
      // Skip if it's in a comment
      if (line.includes('//') || line.includes('/*')) {
        continue;
      }
      
      violations.push({
        id: generateViolationId('hardcoded_text', filePath, lineNum, match.index),
        type: 'hardcoded_text',
        severity: 'HIGH',
        file: filePath,
        line: lineNum,
        column: match.index + 1,
        feature,
        description: `Hardcoded text "${text.substring(0, 50)}${text.length > 50 ? '...' : ''}" found in JSX`,
        suggestion: `Replace with translation: {t("${feature}.key")}`,
        autoFixable: true,
      });
    }
  }
}

function scanForMissingUiIdentifiers(
  filePath: string,
  lines: string[],
  feature: string,
  violations: LegacyViolation[]
): void {
  const nativeInteractiveElements = ['button', 'input', 'select', 'textarea', 'a', 'form'];
  
  for (let i = 0; i < lines.length; i++) {
    const line = lines[i];
    const lineNum = i + 1;
    
    for (const element of nativeInteractiveElements) {
      // Look for native element usage
      const pattern = new RegExp(`<${element}(\\s|>)`, 'g');
      let match;
      
      while ((match = pattern.exec(line)) !== null) {
        // Skip if it's a comment or string
        if (line.includes('//') || line.includes('/*') || line.includes('"') || line.includes("'")) {
          continue;
        }
        
        violations.push({
          id: generateViolationId('missing_ui_identifier', filePath, lineNum, match.index),
          type: 'missing_ui_identifier',
          severity: 'CRITICAL',
          file: filePath,
          line: lineNum,
          column: match.index + 1,
          feature,
          description: `Native <${element}> element used instead of Ui component`,
          suggestion: `Replace with Ui${element.charAt(0).toUpperCase() + element.slice(1)} component with ui prop`,
          autoFixable: true,
        });
      }
    }
  }
}

function scanForMissingTranslations(
  filePath: string,
  lines: string[],
  feature: string,
  violations: LegacyViolation[]
): void {
  for (let i = 0; i < lines.length; i++) {
    const line = lines[i];
    const lineNum = i + 1;
    
    // Look for text content that should be translated
    // Pattern: strings in JSX that are not attributes or expressions
    const textPattern = />([^<{]+)</g;
    let match;
    
    while ((match = textPattern.exec(line)) !== null) {
      const text = match[1].trim();
      
      // Skip if it's empty, too short, or looks like code
      if (!text || text.length < 2 || /^[A-Z_\-0-9]+$/.test(text)) {
        continue;
      }
      
      // Skip if it's already wrapped in t()
      if (line.includes('t(') || line.includes('t("')) {
        continue;
      }
      
      // Skip if it's in a comment
      if (line.includes('//') || line.includes('/*')) {
        continue;
      }
      
      // Skip if it's an attribute value
      if (line.includes('=') && line.match(/=\s*["']/)) {
        continue;
      }
      
      violations.push({
        id: generateViolationId('missing_translation', filePath, lineNum, match.index),
        type: 'missing_translation',
        severity: 'HIGH',
        file: filePath,
        line: lineNum,
        column: match.index + 1,
        feature,
        description: `Text "${text.substring(0, 50)}${text.length > 50 ? '...' : ''}" not wrapped in translation function`,
        suggestion: `Wrap in translation: {t("${feature}.key")}`,
        autoFixable: true,
      });
    }
  }
}

function scanForMissingBindings(
  filePath: string,
  lines: string[],
  feature: string,
  violations: LegacyViolation[]
): void {
  for (let i = 0; i < lines.length; i++) {
    const line = lines[i];
    const lineNum = i + 1;
    
    // Look for UI identifier usage
    const uiPattern = /ui=\{([^}]+)\}/g;
    let match;
    
    while ((match = uiPattern.exec(line)) !== null) {
      const uiValue = match[1].trim();
      
      // Extract string literals
      const stringMatches = uiValue.match(/'([^']+)'/g);
      if (stringMatches) {
        for (const str of stringMatches) {
          const identifier = str.replace(/'/g, '');
          
          if (identifier.includes('.')) {
            // Check if this UI identifier has a corresponding translation
            // This is a simplified check - in reality, we'd need to load the translation registry
            const parts = identifier.split('.');
            if (parts.length >= 4) {
              const expectedKey = `${parts[0]}.${parts[1]}.${parts[3].replace(/-/g, '')}`;
              
              // For now, we'll flag all UI identifiers for manual review
              violations.push({
                id: generateViolationId('missing_binding', filePath, lineNum, match.index),
                type: 'missing_binding',
                severity: 'MEDIUM',
                file: filePath,
                line: lineNum,
                column: match.index + 1,
                feature,
                description: `UI identifier "${identifier}" may be missing translation binding`,
                suggestion: `Ensure translation key "${expectedKey}" exists in i18n files`,
                autoFixable: false,
              });
            }
          }
        }
      }
    }
  }
}

function generateViolationId(type: string, file: string, line: number, column: number): string {
  const fileHash = file.split(/[/\\]/).pop() || 'unknown';
  return `${type}_${fileHash}_${line}_${column}`;
}

function generateJsonReport(report: LegacyViolationReport): void {
  const outputPath = join(process.cwd(), 'docs', 'migration', 'legacy-violations-report.json');
  const fs = require('fs');
  fs.writeFileSync(outputPath, JSON.stringify(report, null, 2), 'utf-8');
  console.log(`\n≡ƒôä JSON report generated: ${outputPath}`);
}

function generateHumanReport(report: LegacyViolationReport): void {
  const reportContent = `# Legacy Violations Report

**Generated:** ${report.scanDate}
**Total Violations:** ${report.totalViolations}

## Executive Summary

- **CRITICAL:** ${report.bySeverity.CRITICAL || 0}
- **HIGH:** ${report.bySeverity.HIGH || 0}
- **MEDIUM:** ${report.bySeverity.MEDIUM || 0}
- **LOW:** ${report.bySeverity.LOW || 0}

## Violations by Type

${Object.entries(report.byType).map(([type, count]) => `- **${type}:** ${count}`).join('\n')}

## Violations by Feature

${Object.entries(report.byFeature).map(([feature, count]) => `- **${feature}:** ${count}`).join('\n')}

## Detailed Violations

${report.violations.map(v => `
### ${v.id}

- **Type:** ${v.type}
- **Severity:** ${v.severity}
- **File:** ${v.file}
- **Line:** ${v.line}
- **Column:** ${v.column}
- **Feature:** ${v.feature}
- **Description:** ${v.description}
- **Suggestion:** ${v.suggestion}
- **Auto-Fixable:** ${v.autoFixable ? 'Yes' : 'No'}
`).join('\n---\n')}

## Migration Priority

1. **CRITICAL** - Fix immediately (breaks UI/i18n rules)
2. **HIGH** - Fix soon (hardcoded text)
3. **MEDIUM** - Fix during migration (missing binding)
4. **LOW** - Fix later (style/legacy patterns)

## Next Steps

1. Run automated fixer for auto-fixable violations
2. Manually review and fix remaining violations
3. Validate fixes with ESLint and TypeScript
4. Run clean state validation
`;

  const outputPath = join(process.cwd(), 'docs', 'migration', 'legacy-violations.md');
  const fs = require('fs');
  fs.writeFileSync(outputPath, reportContent, 'utf-8');
  console.log(`≡ƒôä Human report generated: ${outputPath}`);
}

function main() {
  console.log('≡ƒÜÇ Starting Legacy Violation Scanner...\n');
  
  try {
    const report = scanLegacyViolations();
    generateJsonReport(report);
    generateHumanReport(report);
    
    console.log(`\nΓ£¿ Legacy violation scan complete!`);
    console.log(`\n≡ƒô¥ Next steps:`);
    console.log(`   1. Review the reports in docs/migration/`);
    console.log(`   2. Run automated fixer: npm run fix-legacy-violations`);
    console.log(`   3. Manually fix remaining violations`);
    console.log(`   4. Validate clean state: npm run validate-clean-state`);
  } catch (error) {
    console.error('Legacy violation scan failed:', error);
    process.exit(1);
  }
}

if (require.main === module) {
  main();
}

export { main as scanLegacyViolations };

import { spawn } from 'child_process';
import fs from 'fs';
import path from 'path';

const PID_FILE = path.join(process.cwd(), '.server.pid');

function getServerPid(): number | null {
  if (fs.existsSync(PID_FILE)) {
    const pid = parseInt(fs.readFileSync(PID_FILE, 'utf-8').trim());
    if (!isNaN(pid)) {
      try {
        process.kill(pid, 0);
        return pid;
      } catch {
        // Process not running
        fs.unlinkSync(PID_FILE);
      }
    }
  }
  return null;
}

function saveServerPid(pid: number): void {
  fs.writeFileSync(PID_FILE, pid.toString());
}

function removeServerPid(): void {
  if (fs.existsSync(PID_FILE)) {
    fs.unlinkSync(PID_FILE);
  }
}

function startServer(): void {
  const existingPid = getServerPid();
  if (existingPid) {
    console.log(`Server is already running (PID: ${existingPid})`);
    return;
  }

  console.log('Starting development server...');
  
  const server = spawn('cmd', ['/c', 'start', '/b', 'npm', 'run', 'dev'], {
    stdio: 'inherit',
    shell: false,
    detached: true
  });

  saveServerPid(server.pid!);

  server.unref();

  server.on('error', (error) => {
    console.error('Failed to start server:', error);
    removeServerPid();
  });

  server.on('exit', (code) => {
    console.log(`Server exited with code ${code}`);
    removeServerPid();
  });

  console.log(`Server started (PID: ${server.pid})`);
}

function stopServer(): void {
  const pid = getServerPid();
  if (!pid) {
    console.log('Server is not running');
    return;
  }

  console.log(`Stopping server (PID: ${pid})...`);
  
  try {
    process.kill(pid, 'SIGTERM');
    removeServerPid();
    console.log('Server stopped successfully');
  } catch (error) {
    console.error('Failed to stop server:', error);
  }
}

function clearCache(): void {
  const pid = getServerPid();
  if (pid) {
    console.log('Stopping server before clearing cache...');
    stopServer();
  }

  const cacheDir = path.join(process.cwd(), '.next');
  if (fs.existsSync(cacheDir)) {
    fs.rmSync(cacheDir, { recursive: true, force: true });
    console.log('Cache cleared successfully');
  } else {
    console.log('No cache to clear');
  }
}

function restartServer(): void {
  console.log('Restarting server...');
  stopServer();
  setTimeout(() => {
    startServer();
  }, 1000);
}

function showStatus(): void {
  const pid = getServerPid();
  if (pid) {
    console.log(`Server is running (PID: ${pid})`);
  } else {
    console.log('Server is not running');
  }
}

