'use client';

import { HeroSlider }      from '@/components/home/HeroSlider';
import { CategoriesGrid }  from '@/components/home/CategoriesGrid';
import { FeaturedMarquee } from '@/components/home/FeaturedMarquee';
import { TrendingRibbon }  from '@/components/home/TrendingRibbon';
import { CuratedOffers }   from '@/components/home/CuratedOffers';
import { PromoBanner }     from '@/components/home/PromoBanner';

export default function HomePage() {
  return (
    <div
      id="main-content-container"
      className="px-4 space-y-6"
      style={{ background: 'var(--gova-background)' }}
    >
      <HeroSlider />
      <CategoriesGrid />
      <FeaturedMarquee />
      <TrendingRibbon />
      <CuratedOffers />
      <PromoBanner />
    </div>
  );
}

/**
 * MAOL ΓÇö Ingest Endpoint
 * POST /api/maol/ingest
 *
 * Receives events from the browser client (errors, warnings, DOM summaries).
 * Validates payload structure before writing to the store.
 * Always returns { ok: true } ΓÇö never blocks the client.
 */

import { NextRequest, NextResponse } from 'next/server';
import { isValidMaolSessionId } from '@/shared/maol/session';
import { storeError, storeWarning, storeDomSummary } from '@/lib/maol-store';
import type {
  MaolIngestPayload,
  MaolErrorEvent,
  MaolWarningEvent,
  MaolDomSummary,
} from '@/shared/maol/types';

const OK = NextResponse.json({ ok: true }, { status: 200 });
const IGNORED = NextResponse.json({ ok: true, note: 'ignored' }, { status: 200 });

// Env var check ΓÇö MAOL must be explicitly enabled
function isMaolEnabled(): boolean {
  return process.env.NEXT_PUBLIC_MAOL_ENABLED === 'true';
}

function isValidErrorEvent(e: unknown): e is MaolErrorEvent {
  if (!e || typeof e !== 'object') return false;
  const ev = e as Record<string, unknown>;
  return (
    ev.type === 'error' &&
    typeof ev.message === 'string' &&
    typeof ev.route === 'string' &&
    typeof ev.timestamp === 'number'
  );
}

function isValidWarningEvent(e: unknown): e is MaolWarningEvent {
  if (!e || typeof e !== 'object') return false;
  const ev = e as Record<string, unknown>;
  return (
    ev.type === 'warning' &&
    typeof ev.message === 'string' &&
    typeof ev.route === 'string' &&
    typeof ev.timestamp === 'number' &&
    ['low', 'medium', 'high'].includes(ev.severity as string)
  );
}

function isValidDomSummary(d: unknown): d is MaolDomSummary {
  if (!d || typeof d !== 'object') return false;
  const ds = d as Record<string, unknown>;
  return (
    typeof ds.route === 'string' &&
    typeof ds.timestamp === 'number' &&
    typeof ds.tree === 'object' &&
    ds.tree !== null
  );
}

export async function POST(request: NextRequest): Promise<NextResponse> {
  if (!isMaolEnabled()) return IGNORED;

  let body: unknown;
  try {
    body = await request.json();
  } catch {
    return OK; // Malformed body ΓÇö silently ignore, never block client
  }

  const payload = body as Partial<MaolIngestPayload>;

  const sessionId = payload?.sessionId;
  if (!sessionId || !isValidMaolSessionId(sessionId)) {
    return OK; // Invalid session ΓÇö silently ignore
  }

  // Process events array
  const events = Array.isArray(payload.events) ? payload.events : [];
  for (const event of events) {
    try {
      if (isValidErrorEvent(event)) {
        // Sanitize: cap message and stack length
        storeError(sessionId, {
          ...event,
          message: event.message.substring(0, 1000),
          stack: event.stack?.substring(0, 3000),
        });
      } else if (isValidWarningEvent(event)) {
        storeWarning(sessionId, {
          ...event,
          message: event.message.substring(0, 500),
        });
      }
    } catch {
      // Per-event errors are isolated ΓÇö continue processing
    }
  }

  // Process DOM summary (optional, separate field)
  if (payload.dom && isValidDomSummary(payload.dom)) {
    try {
      storeDomSummary(sessionId, payload.dom);
    } catch {
      // Isolated ΓÇö does not affect event processing
    }
  }

  return OK;
}

// Reject all other methods
export async function GET(): Promise<NextResponse> {
  return NextResponse.json({ error: 'Method not allowed' }, { status: 405 });
}

/**
 * MAOL ΓÇö Agent Query Endpoint
 * GET /api/maol/session/[sessionId]
 *
 * Returns full structured observability data for a given session.
 *
 * ≡ƒöô DEVELOPMENT MODE: NO AUTH REQUIRED! Just call it directly!
 * ≡ƒöÆ PRODUCTION MODE: Requires MAOL_SECRET token (Authorization: Bearer <token>)
 *
 * Response shape:
 * {
 *   sessionId: string,
 *   errors: MaolErrorEvent[],
 *   warnings: MaolWarningEvent[],
 *   dom: MaolDomSummary[],
 *   summary: MaolSessionSummary
 * }
 *
 * @see docs/SERVER_ARCHITECTURE.md for complete documentation
 */

import { NextRequest, NextResponse } from 'next/server';
import { isValidMaolSessionId } from '@/shared/maol/session';
import { getSessionData } from '@/lib/maol-store';

// ---------------------------------------------------------------------------
// Authentication helpers
// ---------------------------------------------------------------------------

/**
 * MAOL IS ALWAYS ENABLED IN DEVELOPMENT MODE!
 * Only check flag in production.
 */
function isMaolEnabled(): boolean {
  if (process.env.NODE_ENV === 'development') {
    return true;
  }
  return process.env.NEXT_PUBLIC_MAOL_ENABLED === 'true';
}

/**
 * Validate the Bearer token from the Authorization header.
 *
 * ≡ƒöô In DEV MODE: always returns true! No auth required!
 * ≡ƒöÆ In PRODUCTION MODE: Requires MAOL_SECRET env var
 *
 * Also accepts x-maol-token header as an alternative.
 */
function isAuthorized(request: NextRequest): boolean {
  // Skip auth in dev mode
  if (process.env.NODE_ENV === 'development') {
    return true;
  }

  const secret = process.env.MAOL_SECRET;

  // If no secret is configured, endpoint is disabled entirely
  if (!secret || secret.trim() === '') return false;

  // Check Authorization: Bearer <token>
  const authHeader = request.headers.get('authorization');
  if (authHeader) {
    const [scheme, token] = authHeader.split(' ');
    if (scheme === 'Bearer' && token === secret) return true;
  }

  // Check x-maol-token header (alternative)
  const tokenHeader = request.headers.get('x-maol-token');
  if (tokenHeader === secret) return true;

  return false;
}

// ---------------------------------------------------------------------------
// Route Handler
// ---------------------------------------------------------------------------

export async function GET(
  request: NextRequest,
  { params }: { params: Promise<{ sessionId: string }> }
): Promise<NextResponse> {
  // 1. Feature flag check
  if (!isMaolEnabled()) {
    return NextResponse.json(
      { error: 'MAOL is not enabled on this server.' },
      { status: 403 }
    );
  }

  // 2. Authentication (skipped in dev mode!)
  if (!isAuthorized(request)) {
    return NextResponse.json(
      { error: 'Unauthorized. Provide a valid MAOL_SECRET token.' },
      { status: 401 }
    );
  }

  // 3. Session ID validation
  const { sessionId } = await params;
  if (!sessionId || !isValidMaolSessionId(sessionId)) {
    return NextResponse.json(
      { error: 'Invalid session ID format. Expected: maol_<alphanumeric>' },
      { status: 400 }
    );
  }

  // 4. Retrieve session data
  const data = getSessionData(sessionId);

  if (!data) {
    return NextResponse.json(
      {
        sessionId,
        errors: [],
        warnings: [],
        dom: [],
        summary: {
          totalErrors: 0,
          totalWarnings: 0,
          totalWarningsByseverity: { low: 0, medium: 0, high: 0 },
          routesVisited: [],
        },
      },
      { status: 200 }
    );
  }

  return NextResponse.json(data, {
    status: 200,
    headers: {
      'Cache-Control': 'no-store, no-cache',
      'X-Maol-Session': sessionId,
    },
  });
}

// Reject all other methods
export async function POST(): Promise<NextResponse> {
  return NextResponse.json({ error: 'Method not allowed' }, { status: 405 });
}

