            {subtitle && <span data-ui-uuid={COMMON_TYPOGRAPHY.P.uuid} className="text-xs text-muted-foreground">{subtitle}</span>}
            {trend && trendValue && (
              <div data-ui-uuid={COMMON_LAYOUT.CONTAINER.uuid} className="flex items-center gap-1">
                {trend === 'up' && <TrendingUp className="h-3 w-3 text-green-600" />}
                {trend === 'down' && <TrendingDown className="h-3 w-3 text-red-600" />}
                {trend === 'neutral' && <Minus className="h-3 w-3 text-muted-foreground" />}
                <span data-ui-uuid={COMMON_LAYOUT.SPAN.uuid} className={`text-xs font-medium ${trend === 'up' ? 'text-green-600' : trend === 'down' ? 'text-red-600' : 'text-muted-foreground'}`}>
                  {trendValue}
                </span>
              </div>
            )}
          </div>
          <div data-ui-uuid={COMMON_LAYOUT.CONTAINER.uuid} className={`rounded-full p-2.5 ${iconColors[iconVariant]}`}>
            <Icon className={`h-5 w-5 ${iconTextColors[iconVariant]}`} />
          </div>
        </div>
      </div>
    </div>
  );
}

