'use client';
import { MERCHANT, COMMON_LAYOUT, COMMON_TYPOGRAPHY, COMMON_COMPONENTS, useTranslation } from '@/platform/ui';

import type { TrustCredential, Achievement, SellerBadge } from '@/lib/merchant/types';
import { getAchievementRarityColor } from '@/lib/merchant/utils';
import { ShieldCheck, Lock, Truck, RefreshCw, Trophy, Star, Zap, Leaf, Crown, Palette, Globe, Flame, Award } from 'lucide-react';

interface TrustCredibilityProps {
  credentials: TrustCredential[];
  achievements: Achievement[];
  badges: SellerBadge[];
  className?: string;
}

const credentialIcons: Record<string, any> = {
  ShieldCheck,
  Lock,
  Truck,
  RefreshCw,
};

const achievementIcons: Record<string, any> = {
  Trophy,
  Star,
  Zap,
  Leaf,
};

const badgeIcons: Record<string, any> = {
  Crown,
  Palette,
  Globe,
  Flame,
};

export function TrustCredibility({
  credentials,
  achievements,
  badges,
  className,
}: TrustCredibilityProps) {
  const { t } = useTranslation();
  return (
    <div data-ui-uuid={MERCHANT.MERCHANT_PROFILE.TRUST.CONTAINER.uuid} className={`overflow-hidden ${className}`}>
      <div data-ui-uuid={COMMON_LAYOUT.CONTAINER.uuid} className="p-6">
        <div data-ui-uuid={COMMON_LAYOUT.CONTAINER.uuid} className="flex items-center gap-2 mb-4">
          <div data-ui-uuid={COMMON_LAYOUT.CONTAINER.uuid} className="rounded-full bg-yellow-100 p-2">
            <Award className="h-5 w-5 text-yellow-600" />
          </div>
          <h2 data-ui-uuid={MERCHANT.MERCHANT_PROFILE.TRUST.TITLE.uuid} className="text-lg">{t(MERCHANT.MERCHANT_PROFILE.TRUST.TITLE)}</h2>
        </div>

        <div data-ui-uuid={COMMON_LAYOUT.CONTAINER.uuid} className="space-y-6">
          <div data-ui-uuid={COMMON_LAYOUT.CONTAINER.uuid} className="grid gap-3 sm:grid-cols-2 lg:grid-cols-4">
            {credentials.map((credential) => {
              const IconComponent = credentialIcons[credential.icon] || ShieldCheck;
              return (
                <div data-ui-uuid={COMMON_LAYOUT.CONTAINER.uuid} key={credential.id} className="flex items-start gap-3 p-3 rounded-lg bg-muted/30 transition-colors hover:bg-muted/50">
                  <div data-ui-uuid={COMMON_LAYOUT.CONTAINER.uuid} className="rounded-full bg-green-100 p-2">
                    <IconComponent className="h-4 w-4 text-green-600" />
                  </div>
                  <div data-ui-uuid={COMMON_LAYOUT.CONTAINER.uuid} className="flex-1 min-w-0">
                    <h4 data-ui-uuid={COMMON_TYPOGRAPHY.H4.uuid} className="font-medium text-sm">{credential.title}</h4>
                    <span data-ui-uuid={COMMON_TYPOGRAPHY.P.uuid} className="text-xs text-muted-foreground mt-0.5">{credential.description}</span>
                  </div>
                </div>
              );
            })}
          </div>

          <div data-ui-uuid={COMMON_LAYOUT.CONTAINER.uuid} className="space-y-3">
            <h4 data-ui-uuid={COMMON_TYPOGRAPHY.H4.uuid} className="font-medium text-sm text-muted-foreground">{t(MERCHANT.MERCHANT_PROFILE.TRUST.ACHIEVEMENTS)}</h4>
            <div data-ui-uuid={COMMON_LAYOUT.CONTAINER.uuid} className="flex flex-wrap gap-2">
              {achievements.map((achievement) => {
                const IconComponent = achievementIcons[achievement.icon] || Trophy;
                return (
                  <span data-ui-uuid={COMMON_COMPONENTS.BADGE.LABEL.uuid} key={achievement.id} className={`gap-1.5 py-1.5 px-3 border ${getAchievementRarityColor(achievement.rarity)}`}>
                    <IconComponent className="h-3.5 w-3.5" />
                    <span data-ui-uuid={COMMON_TYPOGRAPHY.P.uuid} className="font-medium">{achievement.name}</span>
                  </span>
                );
              })}
            </div>
          </div>

          <div data-ui-uuid={COMMON_LAYOUT.CONTAINER.uuid} className="space-y-3">
            <h4 data-ui-uuid={COMMON_TYPOGRAPHY.H4.uuid} className="font-medium text-sm text-muted-foreground">{t(MERCHANT.MERCHANT_PROFILE.TRUST.SELLER_BADGES)}</h4>
            <div data-ui-uuid={COMMON_LAYOUT.CONTAINER.uuid} className="flex flex-wrap gap-2">
              {badges.filter((b) => b.earned).map((badge) => {
                const IconComponent = badgeIcons[badge.icon] || Crown;
                return (
                  <span data-ui-uuid={COMMON_COMPONENTS.BADGE.LABEL.uuid} key={badge.id} className="gap-1.5 py-1.5 px-3 bg-yellow-100 text-yellow-800 border-yellow-200">
                    <IconComponent className="h-3.5 w-3.5" />
                    <span data-ui-uuid={COMMON_TYPOGRAPHY.P.uuid} className="font-medium">{badge.name}</span>
                  </span>
                );
              })}
              {badges.filter((b) => b.earned).length === 0 && (
                <span data-ui-uuid={COMMON_TYPOGRAPHY.P.uuid} className="text-sm text-muted-foreground">{t(MERCHANT.MERCHANT_PROFILE.TRUST.NO_BADGES_EARNED)}</span>
              )}
            </div>
          </div>
        </div>
      </div>
    </div>
  );
}

export default TrustCredibility;

