      <div data-ui-uuid={COMMON_LAYOUT.CONTAINER.uuid} className="space-y-4 max-w-4xl mx-auto">
        <div data-ui-uuid={COMMON_COMPONENTS.CARD.CONTAINER.uuid} className="p-6 cursor-pointer" onClick={() => toggleOption('email-marketing')}>
