          <div data-ui-uuid={COMMON_LAYOUT.CONTAINER.uuid} className="space-y-3">
            {paymentMethods.map((method) => (
              <div data-ui-uuid={COMMON_LAYOUT.CONTAINER.uuid} key={method.id} className="flex items-center gap-2">
                <input type="checkbox" data-ui-uuid={COMMON_FORMS.CHECKBOX.uuid} checked={(payments.paymentMethods || []).includes(method.id as any)} onChange={(e) => {
        const checked = e.target.checked;
        const currentMethods = payments.paymentMethods || [];
        if (checked) {
            updatePayments({
                paymentMethods: [...currentMethods, method.id as any],
            });
        }
        else {
            updatePayments({
                paymentMethods: currentMethods.filter((id) => id !== method.id as any),
            });
        }
    }} />
                <span data-ui-uuid={COMMON_FORMS.LABEL.uuid}>{method.label}</span>
              </div>
            ))}
          </div>
        </div>

        <div data-ui-uuid={COMMON_LAYOUT.CONTAINER.uuid} className="space-y-2">
          <span data-ui-uuid={ONBOARDING.PAYMENTS.CURRENCY_LABEL.uuid}>{t(ONBOARDING.PAYMENTS.CURRENCY_LABEL)}</span>
          <select data-ui-uuid={COMMON_FORMS.SELECT.uuid} value={payments.currency || 'USD'} onChange={(e) => updatePayments({ currency: e.target.value })}>
            {currencyOptions.map((opt) => (
              <option data-ui-uuid={COMMON_FORMS.OPTION.uuid} key={opt.id}>{opt.label}</option>
            ))}
          </select>
        </div>
      </div>
    </div>
  );
}

