function flattenTranslationKeys(
  obj: Record<string, unknown>,
  prefix = '',
  keys = new Set<string>()
): Set<string> {
  for (const [key, value] of Object.entries(obj)) {
    const fullKey = prefix ? `${prefix}.${key}` : key;

    if (value && typeof value === 'object' && !Array.isArray(value)) {
      flattenTranslationKeys(value as Record<string, unknown>, fullKey, keys);
    } else {
      keys.add(fullKey);
    }
  }

  return keys;
}

export function loadAllTranslationKeys(): Set<string> {
  const keys = new Set<string>();
  const localesPath = join(process.cwd(), 'src', 'platform', 'ui', 'i18n', 'locales');

  if (!existsSync(localesPath)) {
    return keys;
  }

  for (const entry of readdirSync(localesPath, { withFileTypes: true })) {
    if (!entry.isDirectory()) continue;

    for (const locale of ['en', 'ar'] as const) {
      const filePath = join(localesPath, entry.name, `${locale}.json`);
      if (!existsSync(filePath)) continue;

      const content = JSON.parse(readFileSync(filePath, 'utf-8')) as Record<string, unknown>;
      flattenTranslationKeys(content, '', keys);
    }
  }

  return keys;
}

export function getRequiredRegistryBindingKeys(): Set<string> {
  const required = new Set<string>();

  for (const ui of ALL_UI_IDENTIFIERS) {
    if (isCategoryUiPath(ui) || !isTranslationRequiredForUiIdentity(ui)) {
      continue;
    }

    required.add(generateTranslationKeyFromUi(ui));
  }

  return required;
}

export function validateRegistryBindings(): {
  isValid: boolean;
  missing: Array<{ ui: string; expectedKey: string }>;
} {
  const availableKeys = loadAllTranslationKeys();
  const missing: Array<{ ui: string; expectedKey: string }> = [];

  for (const ui of ALL_UI_IDENTIFIERS) {
    if (isCategoryUiPath(ui) || !isTranslationRequiredForUiIdentity(ui)) {
      continue;
    }

    const expectedKey = generateTranslationKeyFromUi(ui);
    if (!availableKeys.has(expectedKey)) {
      missing.push({ ui, expectedKey });
    }
  }

  return {
    isValid: missing.length === 0,
    missing,
  };
}

function main() {
  console.log('≡ƒöù Validating UI registry ΓåÆ translation bindings...\n');

  const { isValid, missing } = validateRegistryBindings();

  if (!isValid) {
    console.error(`Γ¥î ${missing.length} missing registry binding(s):\n`);
    for (const entry of missing) {
      console.error(`   UI path: ${entry.ui}`);
      console.error(`   Expected translation key: "${entry.expectedKey}"`);
      console.error('');
    }
    console.error(
      'Add the missing keys to src/platform/ui/i18n/locales/<feature>/en.json and ar.json'
    );
    console.error('Key shape follows generateTranslationKeyFromUi (page.section.camelCaseElement).');
    process.exit(1);
  }

  console.log(`Γ£à All ${ALL_UI_IDENTIFIERS.length} registry identities have bound translations.`);
}

if (require.main === module) {
  main();
}

import { readdirSync, readFileSync, existsSync } from 'fs';
import { join } from 'path';

interface ValidationResult {
  feature: string;
  isValid: boolean;
  errors: string[];
}

interface TranslationStructure {
  [key: string]: string | TranslationStructure;
}

/**
 * Get all keys from a nested object as dot-notation paths
 */
function getObjectKeys(obj: TranslationStructure, prefix = ''): string[] {
  const keys: string[] = [];
  
  for (const key in obj) {
    const value = obj[key];
    const fullKey = prefix ? `${prefix}.${key}` : key;
    
    if (typeof value === 'object' && value !== null) {
      keys.push(...getObjectKeys(value, fullKey));
    } else {
      keys.push(fullKey);
    }
  }
  
  return keys;
}

function getLeafName(key: string): string {
  return key.split('.').pop() ?? key;
}

function validateLeafNaming(keys: Set<string>, feature: string, errors: string[]): void {
  for (const key of keys) {
    const leaf = getLeafName(key);
    if (leaf.includes('-')) {
      errors.push(
        `Invalid leaf key in ${feature}: ${key}. Use camelCase for leaf text keys; section names may remain kebab-case.`
      );
    }
  }
}

/**
 * Compare two translation structures and return differences
 */
function compareTranslations(
  en: TranslationStructure,
  ar: TranslationStructure,
  feature: string
): ValidationResult {
  const errors: string[] = [];
  
  const enKeys = new Set(getObjectKeys(en));
  const arKeys = new Set(getObjectKeys(ar));

  validateLeafNaming(enKeys, feature, errors);
  validateLeafNaming(arKeys, feature, errors);
  
  // Check for missing keys in Arabic
  for (const key of enKeys) {
    if (!arKeys.has(key)) {
      errors.push(`Missing key in ar.json: ${key}`);
    }
  }
  
  // Check for extra keys in Arabic
  for (const key of arKeys) {
    if (!enKeys.has(key)) {
      errors.push(`Extra key in ar.json (not in en.json): ${key}`);
    }
  }
  
  return {
    feature,
    isValid: errors.length === 0,
    errors,
  };
}

/**
 * Load translation file
 */
function loadTranslationFile(feature: string, locale: string): TranslationStructure | null {
  const localesPath = join(process.cwd(), 'src', 'platform', 'ui', 'i18n', 'locales');
  const filePath = join(localesPath, feature, `${locale}.json`);
  
  if (!existsSync(filePath)) {
    return null;
  }
  
  try {
    const content = readFileSync(filePath, 'utf-8');
    return JSON.parse(content);
  } catch (error) {
    console.error(`Error loading ${filePath}:`, error);
    return null;
  }
}

/**
 * Validate all feature translations
 */
function validateAllTranslations(): ValidationResult[] {
  const localesPath = join(process.cwd(), 'src', 'platform', 'ui', 'i18n', 'locales');
  const results: ValidationResult[] = [];
  
  if (!existsSync(localesPath)) {
    console.error('Locales directory not found');
    return results;
  }
  
  const features = readdirSync(localesPath, { withFileTypes: true })
    .filter(dirent => dirent.isDirectory())
    .map(dirent => dirent.name);
  
  for (const feature of features) {
    const enTranslations = loadTranslationFile(feature, 'en');
    const arTranslations = loadTranslationFile(feature, 'ar');
    
    if (!enTranslations || !arTranslations) {
      results.push({
        feature,
        isValid: false,
        errors: [
          !enTranslations ? 'Missing en.json' : '',
          !arTranslations ? 'Missing ar.json' : '',
        ].filter(Boolean),
      });
      continue;
    }
    
    const comparison = compareTranslations(enTranslations, arTranslations, feature);
    results.push(comparison);
  }
  
  return results;
}

/**
 * Main validation function
 */
function main() {
  console.log('≡ƒöì Validating translations...\n');
  
  const results = validateAllTranslations();
  
  let hasErrors = false;
  
  for (const result of results) {
    if (!result.isValid) {
      hasErrors = true;
      console.error(`Γ¥î ${result.feature}:`);
      for (const error of result.errors) {
        console.error(`   - ${error}`);
      }
      console.error('');
    } else {
      console.log(`Γ£à ${result.feature}: Valid`);
    }
  }
  
  if (hasErrors) {
    console.error('\nΓ¥î Translation validation failed!');
    console.error('Please fix the errors above before committing or building.');
    process.exit(1);
  } else {
    console.log('\nΓ£à All translations are valid!');
    process.exit(0);
  }
}

// Run validation if called directly
if (require.main === module) {
  main();
}

export { validateAllTranslations, compareTranslations };

