/**
 * Strict Binding Enforcement at Type Level
 * 
 * This module enforces that UI identifiers and translation keys are structurally bound
 * at the type level, ensuring zero possibility of mismatched usage.
 */

import type { UiIdentifier, UiParam } from '../../registry/registry';
import {
  generateTranslationKeyFromUi,
  validateBinding,
  type BindingValidationResult,
} from './registry-binding';
import {
  boundTranslation,
  type TranslateFn,
} from './boundTranslation';
import type { TranslationKey } from '../keys';

export type { TranslateFn, TranslationKey };
export { boundTranslation };

/**
 * Bound UI Context - Provides type-safe coupling between UI and translation
 */
export interface BoundUIContext {
  ui: UiIdentifier;
  translationKey: string;
  isValid: boolean;
}

/**
 * Create a bound UI context
 * This ensures that the UI identifier and translation key are properly coupled
 */
export function createBoundUI(
  ui: UiIdentifier,
  translationKey: string,
  availableTranslationKeys: Set<string>
): BoundUIContext {
  const validation = validateBinding(ui, translationKey, availableTranslationKeys);
  
  return {
    ui,
    translationKey,
    isValid: validation.isValid,
  };
}

/**
 * Type-safe hook for using bound UI components
 * Ensures that UI identifiers are always used with their corresponding translation keys
 */
export function useBoundUI(
  ui: UiIdentifier,
  availableTranslationKeys: Set<string>
): { ui: UiIdentifier; translationKey: string } {
  const translationKey = generateTranslationKeyFromUi(ui);
  
  // Validate that the translation key exists
  if (!availableTranslationKeys.has(translationKey)) {
    throw new Error(
      `UI identifier "${ui}" requires translation key "${translationKey}" which does not exist. ` +
      `Please add this translation to your i18n files.`
    );
  }
  
  return {
    ui,
    translationKey,
  };
}

/**
 * Type-safe translation from UI identity (use via useTranslation().t in components).
 */
export function useBoundTranslation(
  ui: UiParam,
  t: TranslateFn,
  fallback?: string
): string {
  return boundTranslation(ui, t, fallback);
}

/**
 * Validate that a translation key is used within its proper UI context
 */
export function validateTranslationContext(
  translationKey: string,
  uiContext: UiIdentifier | null
): BindingValidationResult {
  if (!uiContext) {
    return {
      isValid: false,
      errors: [{
        type: 'MISSING_UI_CONTEXT' as any,
        translationKey,
        message: `Translation key "${translationKey}" is used without UI context. All translations must be used within a UI component context.`,
      }],
      warnings: [],
    };
  }
  
  const expectedKey = generateTranslationKeyFromUi(uiContext);
  
  if (translationKey !== expectedKey) {
    return {
      isValid: false,
      errors: [{
        type: 'CONTEXT_MISMATCH' as any,
        ui: uiContext,
        translationKey,
        message: `Translation key "${translationKey}" does not match expected key "${expectedKey}" for UI context "${uiContext}".`,
      }],
      warnings: [],
    };
  }
  
  return {
    isValid: true,
    errors: [],
    warnings: [],
  };
}

/**
 * Type-safe bound UI component props
 */
// BoundUI component removed - JSX syntax not supported in .ts files
// Use the functional APIs instead: useBoundUI, useBoundTranslation, validateTranslationContext

/**
 * Validate complete binding for a component
 * Ensures all UI identifiers used in a component have corresponding translations
 */
export function validateComponentBindings(
  uiIdentifiers: UiIdentifier[],
  availableTranslationKeys: Set<string>
): BindingValidationResult {
  const errors: any[] = [];
  const warnings: any[] = [];
  
  for (const ui of uiIdentifiers) {
    const expectedKey = generateTranslationKeyFromUi(ui);
    
    if (!availableTranslationKeys.has(expectedKey)) {
      errors.push({
        type: 'MISSING_TRANSLATION' as any,
        ui,
        translationKey: expectedKey,
        message: `UI identifier "${ui}" requires translation key "${expectedKey}" which does not exist.`,
      });
    }
  }
  
  return {
    isValid: errors.length === 0,
    errors,
    warnings,
  };
}

/**
 * Get all required translation keys for a set of UI identifiers
 */
export function getRequiredTranslationKeys(uiIdentifiers: UiIdentifier[]): Set<string> {
  const keys = new Set<string>();
  
  for (const ui of uiIdentifiers) {
    const key = generateTranslationKeyFromUi(ui);
    keys.add(key);
  }
  
  return keys;
}

/**
 * Validate that all required translation keys exist
 */
export function validateRequiredTranslations(
  uiIdentifiers: UiIdentifier[],
  availableTranslationKeys: Set<string>
): { isValid: boolean; missing: string[] } {
  const requiredKeys = getRequiredTranslationKeys(uiIdentifiers);
  const missing: string[] = [];
  
  for (const key of requiredKeys) {
    if (!availableTranslationKeys.has(key)) {
      missing.push(key);
    }
  }
  
  return {
    isValid: missing.length === 0,
    missing,
  };
}

import { Feature } from './types';
import type { TranslationKey } from '../keys';

/**
 * Enforce feature localization boundary
 * Features can only access their own dictionary and common dictionary
 * 
 * @param currentFeature - The feature requesting the translation
 * @param requestedFeature - The feature being accessed in the translation key
 * @throws Error if boundary violation detected
 */
export function enforceLocalizationBoundary(
  currentFeature: Feature,
  requestedFeature: string
): void {
  // Allow access to common dictionary namespaces
  const COMMON_NAMESPACES = ['common', 'navigation', 'buttons', 'validation', 'messages', 'shared-layout', 'error-boundary'];
  if (COMMON_NAMESPACES.includes(requestedFeature)) {
    return;
  }

  // Allow access to own dictionary
  if (requestedFeature === currentFeature) {
    return;
  }

  // Boundary violation detected
  throw new Error(
    `Localization boundary violation: Feature "${currentFeature}" cannot access translations from feature "${requestedFeature}". ` +
    `Features can only access their own dictionary and the common dictionary.`
  );
}

/**
 * Extract feature from translation key
 * @param key - Translation key in dot notation (e.g., "home.title")
 * @returns The feature name from the key
 */
export function extractFeatureFromKey(key: TranslationKey): string {
  const parts = key.split('.');
  if (parts.length === 0) {
    return 'common'; // Default to common if no namespace
  }
  return parts[0];
}

/**
 * Validate translation key respects localization boundary
 * @param key - Translation key to validate
 * @param currentFeature - The current feature context
 * @throws Error if boundary violation detected
 */
export function validateTranslationKey(key: TranslationKey, currentFeature: Feature): void {
  const requestedFeature = extractFeatureFromKey(key);
  enforceLocalizationBoundary(currentFeature, requestedFeature);
}

import { Locale, Feature, TranslationDictionary } from './types';
import { resolveFeatureScope } from './featureScope';

/**
 * Cache entry with timestamp for potential TTL
 */
interface CacheEntry {
  dictionary: TranslationDictionary;
  timestamp: number;
}

/**
 * Server-side cache layer for merged dictionaries
 * Cache key format: locale:feature (e.g., "ar:dashboard", "en:auth")
 */
class DictionaryCache {
  private cache: Map<string, CacheEntry> = new Map();
  private readonly DEFAULT_TTL = 5 * 60 * 1000; // 5 minutes

  /**
   * Generate cache key from locale and feature
   */
  private generateKey(locale: Locale, feature: Feature): string {
    return `${locale}:${feature}`;
  }

  /**
   * Get dictionary from cache
   */
  get(locale: Locale, feature: Feature): TranslationDictionary | null {
    const key = this.generateKey(locale, feature);
    const entry = this.cache.get(key);

    if (!entry) {
      return null;
    }

    // Check if cache entry has expired
    if (Date.now() - entry.timestamp > this.DEFAULT_TTL) {
      this.cache.delete(key);
      return null;
    }

    return entry.dictionary;
  }

  /**
   * Set dictionary in cache
   */
  set(locale: Locale, feature: Feature, dictionary: TranslationDictionary): void {
    const key = this.generateKey(locale, feature);
    this.cache.set(key, {
      dictionary,
      timestamp: Date.now(),
    });
  }

  /**
   * Clear cache for specific locale and feature
   */
  clear(locale?: Locale, feature?: Feature): void {
    if (locale && feature) {
      const key = this.generateKey(locale, feature);
      this.cache.delete(key);
    } else if (locale) {
      // Clear all entries for a specific locale
      for (const key of this.cache.keys()) {
        if (key.startsWith(`${locale}:`)) {
          this.cache.delete(key);
        }
      }
    } else {
      // Clear entire cache
      this.cache.clear();
    }
  }

  /**
   * Get cache statistics
   */
  getStats(): { size: number; keys: string[] } {
    return {
      size: this.cache.size,
      keys: Array.from(this.cache.keys()),
    };
  }
}

// Global cache instance
const dictionaryCache = new DictionaryCache();

/**
 * Deep merge two dictionaries with feature taking precedence over common
 */
function deepMerge(base: TranslationDictionary, override: TranslationDictionary): TranslationDictionary {
  const result = { ...base };

  for (const key in override) {
    if (override.hasOwnProperty(key)) {
      const baseValue = result[key];
      const overrideValue = override[key];

      if (
        typeof baseValue === 'object' &&
        baseValue !== null &&
        !Array.isArray(baseValue) &&
        typeof overrideValue === 'object' &&
        overrideValue !== null &&
        !Array.isArray(overrideValue)
      ) {
        // Both are objects, merge recursively
        result[key] = deepMerge(
          baseValue as TranslationDictionary,
          overrideValue as TranslationDictionary
        );
      } else {
        // Override with feature value
        result[key] = overrideValue;
      }
    }
  }

  return result;
}

/**
 * Load common dictionary for a locale
 */
async function loadCommonDictionary(locale: Locale): Promise<TranslationDictionary> {
  try {
    const module = await import(`@/platform/ui/i18n/locales/common/${locale}.json`);
    return module.default;
  } catch (error) {
    console.warn(`Common dictionary not found for locale: ${locale}`);
    return {};
  }
}

/**
 * Load feature-specific dictionary for a locale
 */
async function loadFeatureDictionary(feature: Feature, locale: Locale): Promise<TranslationDictionary> {
  try {
    const module = await import(`@/platform/ui/i18n/locales/${feature}/${locale}.json`);
    return module.default;
  } catch (error) {
    console.warn(`Feature dictionary not found for feature: ${feature}, locale: ${locale}`);
    return {};
  }
}

/**
 * Load and deep-merge all feature namespaces for a route scope.
 */
export async function getMergedDictionary(
  locale: Locale,
  feature: Feature
): Promise<TranslationDictionary> {
  const scope = resolveFeatureScope(feature);
  const uniqueScope = [...new Set(scope)];

  const dictionaries = await Promise.all(
    uniqueScope.map((scopeFeature) =>
      scopeFeature === 'common'
        ? loadCommonDictionary(locale)
        : loadFeatureDictionary(scopeFeature, locale)
    )
  );

  return dictionaries.reduce<TranslationDictionary>(
    (merged, dict) => deepMerge(merged, dict),
    {}
  );
}

/**
 * Get merged dictionary for a feature and locale (full route scope).
 */
export async function getDictionary(locale: Locale, feature: Feature): Promise<TranslationDictionary> {
  return getMergedDictionary(locale, feature);
}

/**
 * Get merged dictionary with server-side caching
 * Uses cache key format: locale:feature (e.g., "ar:dashboard", "en:auth")
 */
export async function getDictionaryCached(locale: Locale, feature: Feature): Promise<TranslationDictionary> {
  // Check cache first
  const cached = dictionaryCache.get(locale, feature);
  if (cached) {
    return cached;
  }

  // Load and cache the dictionary
  const dictionary = await getDictionary(locale, feature);
  dictionaryCache.set(locale, feature, dictionary);
  
  return dictionary;
}

/**
 * Clear dictionary cache
 * Useful for development or when translations are updated
 */
export function clearDictionaryCache(locale?: Locale, feature?: Feature): void {
  dictionaryCache.clear(locale, feature);
}

/**
 * Get cache statistics for debugging
 */
export function getDictionaryCacheStats(): { size: number; keys: string[] } {
  return dictionaryCache.getStats();
}

/** Features merged into the single app-wide dictionary */
export const APP_DICTIONARY_FEATURES: readonly Feature[] = [
  'common',
  'splash',
  'home',
  'auth',
  'shared-layout',
  'error-boundary',
  'settings',
  'merchant',
  'onboarding',
  'signup',
] as const;

const APP_DICTIONARY_CACHE_KEY = '__app__' as Feature;

/**
 * Load the full application dictionary (all route scopes) in one merge.
 */
export async function getAppDictionary(locale: Locale): Promise<TranslationDictionary> {
  const uniqueFeatures = [...new Set(APP_DICTIONARY_FEATURES)];

  const dictionaries = await Promise.all(
    uniqueFeatures.map((scopeFeature) =>
      scopeFeature === 'common'
        ? loadCommonDictionary(locale)
        : loadFeatureDictionary(scopeFeature, locale)
    )
  );

  return dictionaries.reduce<TranslationDictionary>(
    (merged, dict) => deepMerge(merged, dict),
    {}
  );
}

/**
 * Cached full application dictionary for root layout SSR.
 */
export async function getAppDictionaryCached(locale: Locale): Promise<TranslationDictionary> {
  const cached = dictionaryCache.get(locale, APP_DICTIONARY_CACHE_KEY);
  if (cached) {
    return cached;
  }

  const dictionary = await getAppDictionary(locale);
  dictionaryCache.set(locale, APP_DICTIONARY_CACHE_KEY, dictionary);
  return dictionary;
}

