'use client';

import { createContext, useContext, useState, useEffect, useCallback, ReactNode, useMemo } from 'react';
import { usePathname } from 'next/navigation';
import { Locale, I18nContext, TranslationDictionary } from './types';
import { getAppDictionary } from './getDictionary';
import { resolveFeatureFromPathname } from './i18n-route-manifest';
import { useUnifiedStore } from '@/store/unified.store';

const I18nContextInstance = createContext<I18nContext | undefined>(undefined);

interface I18nProviderProps {
  children: ReactNode;
  initialLocale: Locale;
  initialDictionary: TranslationDictionary;
}

/**
 * Single root i18n provider ΓÇö loads full app dictionary once; route feature syncs via pathname.
 */
export function I18nProvider({
  children,
  initialLocale,
  initialDictionary,
}: I18nProviderProps) {
  const pathname = usePathname();
  const routeFeature = useMemo(
    () => resolveFeatureFromPathname(pathname ?? '/'),
    [pathname]
  );

  const { language: locale, setLanguage: setLocaleSSOT } = useUnifiedStore();
  const [dictionary, setDictionary] = useState<TranslationDictionary>(initialDictionary);

  const loadDictionary = useCallback(
    async (targetLocale: Locale) => getAppDictionary(targetLocale),
    []
  );

  useEffect(() => {
    if (locale === initialLocale) {
      return;
    }

    let cancelled = false;
    loadDictionary(locale).then((dict) => {
      if (!cancelled) {
        setDictionary(dict);
      }
    });

    return () => {
      cancelled = true;
    };
  }, [locale, initialLocale, loadDictionary]);

  const handleSetLocale = async (newLocale: Locale) => {
    setLocaleSSOT(newLocale);
    const newDictionary = await loadDictionary(newLocale);
    setDictionary(newDictionary);
  };

  const contextValue: I18nContext = {
    locale,
    setLocale: handleSetLocale,
    dictionary,
    feature: routeFeature,
  };

  return (
    <I18nContextInstance.Provider value={contextValue}>
      {children}
    </I18nContextInstance.Provider>
  );
}

export function useI18nContext(): I18nContext {
  const context = useContext(I18nContextInstance);
  if (!context) {
    throw new Error('useI18nContext must be used within I18nProvider');
  }
  return context;
}

import type { TranslationKey } from '../keys';
import { TranslationDictionary } from './types';

const missingKeys = new Set<string>();

/**
 * Safely resolve a dot-notation key from a dictionary.
 * In development, missing keys log once and surface a visible marker.
 */
export function t(
  key: TranslationKey,
  dictionary: TranslationDictionary,
  fallback?: string
): string {
  const keys = key.split('.');
  let value: unknown = dictionary;

  for (const k of keys) {
    if (value && typeof value === 'object' && k in (value as object)) {
      value = (value as TranslationDictionary)[k];
    } else {
      if (process.env.NODE_ENV === 'development') {
        if (!missingKeys.has(key)) {
          missingKeys.add(key);
          console.error(
            `[i18n] Missing translation key: "${key}". Run npm run i18n:sync, then npm run i18n:validate. If this came from a UI identity, check the generated key shape: feature.section.camelCaseElement.`
          );
        }
        return fallback ?? `[missing:${key}]`;
      }
      return fallback ?? '';
    }
  }

  if (typeof value !== 'string') {
    if (process.env.NODE_ENV === 'development') {
      if (!missingKeys.has(key)) {
        missingKeys.add(key);
        console.error(`[i18n] Translation key "${key}" is not a string.`);
      }
      return fallback ?? `[missing:${key}]`;
    }
    return fallback ?? '';
  }

  return value;
}

/**
 * Type-safe translation function generator
 */
export function createTranslator(dictionary: TranslationDictionary) {
  return (key: TranslationKey, fallback?: string) => t(key, dictionary, fallback);
}

