import { useI18nContext } from './provider';
import { t as translateKey } from './t';
import { validateTranslationKey } from './enforceBoundary';
import {
  resolveTranslationKey,
  type TranslationSource,
} from './resolveTranslationSource';

export type TranslateFn = (source: TranslationSource, fallback?: string) => string;

/**
 * Translation hook ΓÇö single `t()` for UI identities and translation keys.
 */
export function useTranslation() {
  const { locale, setLocale, dictionary, feature } = useI18nContext();

  const t: TranslateFn = (source, fallback) => {
    const key = resolveTranslationKey(source);

    if (!key) {
      if (process.env.NODE_ENV === 'development') {
        console.warn('[i18n] No translation key for source:', source);
      }
      return fallback ?? '';
    }

    try {
      validateTranslationKey(key, feature);
    } catch (error) {
      console.warn(error);
    }

    const result = translateKey(key, dictionary, fallback);

    if (result === key && process.env.NODE_ENV === 'development') {
      console.warn(`[i18n] Missing translation for key "${key}" (feature scope: ${feature})`);
    }

    return result;
  };

  return {
    t,
    locale,
    setLocale,
    feature,
  };
}

import { cookies } from 'next/headers';
import { Locale } from '../core/types';
import { LocaleStorageAdapter } from './LocaleStorageAdapter';

/**
 * Cookie-based locale storage adapter
 * Used for server-side locale persistence
 */
export class CookieLocaleAdapter implements LocaleStorageAdapter {
  private readonly COOKIE_NAME = 'locale';
  private readonly MAX_AGE = 365 * 24 * 60 * 60; // 1 year in seconds

  async getLocale(): Promise<Locale | null> {
    try {
      const cookieStore = await cookies();
      const cookie = cookieStore.get(this.COOKIE_NAME);
      
      if (cookie && (cookie.value === 'en' || cookie.value === 'ar')) {
        return cookie.value as Locale;
      }
      
      return null;
    } catch (error) {
      console.error('Error reading locale from cookie:', error);
      return null;
    }
  }

  async setLocale(locale: Locale): Promise<void> {
    try {
      const cookieStore = await cookies();
      cookieStore.set(this.COOKIE_NAME, locale, {
        maxAge: this.MAX_AGE,
        path: '/',
        httpOnly: false,
        sameSite: 'lax',
      });
    } catch (error) {
      console.error('Error setting locale in cookie:', error);
    }
  }

  async removeLocale(): Promise<void> {
    try {
      const cookieStore = await cookies();
      cookieStore.delete(this.COOKIE_NAME);
    } catch (error) {
      console.error('Error removing locale from cookie:', error);
    }
  }

  isAvailable(): boolean {
    // Cookie adapter is always available in Next.js
    return true;
  }
}

import { Locale } from '../core/types';
import { LocaleStorageAdapter } from './LocaleStorageAdapter';

/**
 * IndexedDB-based locale storage adapter
 * Used for client-side locale persistence
 * Prepared for future migration from cookies to IndexedDB
 */
export class IndexedDbLocaleAdapter implements LocaleStorageAdapter {
  private readonly DB_NAME = 'gova-i18n';
  private readonly DB_VERSION = 1;
  private readonly STORE_NAME = 'settings';
  private readonly LOCALE_KEY = 'locale';
  private db: IDBDatabase | null = null;

  async getLocale(): Promise<Locale | null> {
    try {
      const db = await this.getDatabase();
      return new Promise((resolve, reject) => {
        const transaction = db.transaction(this.STORE_NAME, 'readonly');
        const store = transaction.objectStore(this.STORE_NAME);
        const request = store.get(this.LOCALE_KEY);
        
        request.onsuccess = () => {
          const result = request.result;
          if (result && (result === 'en' || result === 'ar')) {
            resolve(result as Locale);
          } else {
            resolve(null);
          }
        };
        
        request.onerror = () => {
          reject(new Error('Failed to read locale from IndexedDB'));
        };
      });
    } catch (error) {
      console.error('Error reading locale from IndexedDB:', error);
      return null;
    }
  }

  async setLocale(locale: Locale): Promise<void> {
    try {
      const db = await this.getDatabase();
      return new Promise((resolve, reject) => {
        const transaction = db.transaction(this.STORE_NAME, 'readwrite');
        const store = transaction.objectStore(this.STORE_NAME);
        const request = store.put(locale, this.LOCALE_KEY);
        
        request.onsuccess = () => resolve();
        request.onerror = () => reject(new Error('Failed to set locale in IndexedDB'));
      });
    } catch (error) {
      console.error('Error setting locale in IndexedDB:', error);
    }
  }

  async removeLocale(): Promise<void> {
    try {
      const db = await this.getDatabase();
      return new Promise((resolve, reject) => {
        const transaction = db.transaction(this.STORE_NAME, 'readwrite');
        const store = transaction.objectStore(this.STORE_NAME);
        const request = store.delete(this.LOCALE_KEY);
        
        request.onsuccess = () => resolve();
        request.onerror = () => reject(new Error('Failed to remove locale from IndexedDB'));
      });
    } catch (error) {
      console.error('Error removing locale from IndexedDB:', error);
    }
  }

  isAvailable(): boolean {
    // IndexedDB is available in most modern browsers
    return typeof window !== 'undefined' && 'indexedDB' in window;
  }

  private async getDatabase(): Promise<IDBDatabase> {
    if (this.db) {
      return this.db;
    }

    return new Promise((resolve, reject) => {
      const request = indexedDB.open(this.DB_NAME, this.DB_VERSION);

      request.onerror = () => {
        reject(new Error('Failed to open IndexedDB'));
      };

      request.onsuccess = () => {
        this.db = request.result;
        resolve(this.db);
      };

      request.onupgradeneeded = (event) => {
        const db = (event.target as IDBOpenDBRequest).result;
        
        if (!db.objectStoreNames.contains(this.STORE_NAME)) {
          db.createObjectStore(this.STORE_NAME);
        }
      };
    });
  }

  /**
   * Close the database connection
   */
  async close(): Promise<void> {
    if (this.db) {
      this.db.close();
      this.db = null;
    }
  }
}

