/**
 * Playwright Testing Utilities for Persistent UI Identity Platform
 * 
 * These helpers allow test scripts to select DOM elements using stable UI IDs 
 * instead of fragile CSS selectors or layout-dependent xpath queries.
 * 
 * @example
 * import { getByUiId } from '@/shared/ui-test-helpers';
 * 
 * test('should submit login form', async ({ page }) => {
 *   await page.goto('/login');
 *   await getByUiId(page, 'UI_AUTH_LOGIN_EMAIL_INPUT').fill('user@example.com');
 *   await getByUiId(page, 'UI_AUTH_LOGIN_PASSWORD_INPUT').fill('password123');
 *   await getByUiId(page, 'UI_AUTH_LOGIN_SUBMIT_BUTTON').click();
 * });
 */

/**
 * Locate a DOM element by its immutable UI UUID.
 * 
 * @param page Playwright Page object (typed as any to prevent build dependencies)
 * @param uuid Immutable UI UUID
 * @returns Playwright Locator
 */
export function getByUiUuid(page: any, uuid: string): any {
  if (!page || typeof page.locator !== 'function') {
    throw new Error('[UI Test Helpers] Invalid Page object passed to getByUiUuid.');
  }
  return page.locator(`[data-ui-uuid="${uuid}"]`);
}

/**
 * Locate a specific dynamic UI instance by immutable registry UUID and runtime instance ID.
 */
export function getByUiInstance(page: any, uuid: string, instanceId: string | number): any {
  if (!page || typeof page.locator !== 'function') {
    throw new Error('[UI Test Helpers] Invalid Page object passed to getByUiInstance.');
  }
  return page.locator(`[data-ui-identity-key="${uuid}:${String(instanceId)}"]`);
}

/**
 * Locate a DOM element by the precomputed UI identity key.
 */
export function getByUiIdentityKey(page: any, identityKey: string): any {
  if (!page || typeof page.locator !== 'function') {
    throw new Error('[UI Test Helpers] Invalid Page object passed to getByUiIdentityKey.');
  }
  return page.locator(`[data-ui-identity-key="${identityKey}"]`);
}

/**
 * Locate a DOM element by its stable UI Identity ID.
 * 
 * @param page Playwright Page object (typed as any to prevent build dependencies)
 * @param id Stable UI Identity ID (e.g., 'UI_AUTH_LOGIN_SUBMIT_BUTTON')
 * @returns Playwright Locator
 */
/**
 * @deprecated Use getByUiUuid ΓÇö data-ui-id is no longer emitted on DOM elements.
 */
export function getByUiId(page: any, id: string): any {
  if (!page || typeof page.locator !== 'function') {
    throw new Error('[UI Test Helpers] Invalid Page object passed to getByUiId.');
  }
  return page.locator(`[data-ui-id="${id}"]`);
}

/**
 * Locate a DOM element by its hierarchical UI Path.
 * Useful as a secondary fallback or for validation assertions.
 * 
 * @param page Playwright Page object
 * @param path Hierarchical UI Path (e.g., 'auth.login.form.submit-button')
 * @returns Playwright Locator
 */
/**
 * @deprecated Use getByUiUuid ΓÇö data-ui-path is no longer emitted on DOM elements.
 */
export function getByUiPath(page: any, path: string): any {
  if (!page || typeof page.locator !== 'function') {
    throw new Error('[UI Test Helpers] Invalid Page object passed to getByUiPath.');
  }
  return page.locator(`[data-ui-path="${path}"]`);
}

/**
 * Locate all DOM elements belonging to a specific feature area.
 * 
 * @param page Playwright Page object
 * @param feature Feature name (e.g., 'auth', 'shared-layout')
 * @returns Playwright Locator
 */
export function getByUiFeature(page: any, feature: string): any {
  if (!page || typeof page.locator !== 'function') {
    throw new Error('[UI Test Helpers] Invalid Page object passed to getByUiFeature.');
  }
  return page.locator(`[data-ui-feature="${feature}"]`);
}

/**
 * UI Telemetry & Visual Inspector Foundation
 * 
 * This module provides the telemetry extraction layer for analytics and 
 * reverse lookup capabilities for inspector tools and developer diagnostics.
 */

import {
  getUiIdentityByUuid,
  getUiIdentity,
  getUiIdentityUuid,
  type UiIdentity,
  type UiParam,
} from '../registry/registry';
import { UI_SOURCE_INDEX_BY_UUID } from '../registry/source-index';

export interface UiTelemetryData {
  uuid: string;
  instanceId?: string | undefined;
  identityKey: string;
  id: string;
  path: string;
  feature: string;
  timestamp: string;
}

export interface UiErrorTelemetryData extends UiTelemetryData {
  errorMessage: string;
  errorStack?: string | undefined;
}

export interface InspectorLocationInfo extends UiIdentity {
  sourceFile: string;
  sourceComponent: string;
  sourceLine: number;
}

/**
 * Helper to resolve UI Identity from either an HTMLElement or a UiParam.
 */
export function resolveTelemetryIdentity(target: HTMLElement | UiParam | null): UiIdentity | null {
  if (!target) return null;
  if (typeof target === 'object' && 'getAttribute' in target && typeof target.getAttribute === 'function') {
    const uuid = target.getAttribute('data-ui-uuid');
    if (uuid) {
      return getUiIdentityByUuid(uuid) || null;
    }
    return null;
  }
  return getUiIdentity(target as UiParam) || null;
}

/**
 * Resolve UI Identity metadata and source file location from a DOM element or UI identity object.
 * Essential for the Visual Inspector, error logs, and AI Agent navigation.
 * 
 * @param target The DOM element or UiParam
 * @returns Metadata including source file and component name, or null if not registered
 */
export function resolveElementIdentity(target: HTMLElement | UiParam | null): InspectorLocationInfo | null {
  const identity = resolveTelemetryIdentity(target);
  if (!identity) return null;

  // Get source code mapping
  const sourceLocation = UI_SOURCE_INDEX_BY_UUID[identity.uuid];

  return {
    ...identity,
    sourceFile: sourceLocation?.sourceFile || 'unknown',
    sourceComponent: sourceLocation?.sourceComponent || 'unknown',
    sourceLine: sourceLocation?.sourceLine || 1,
  };
}

/**
 * Track an interaction event.
 * Extracts the stable UI ID, path, and feature automatically.
 * 
 * @param target The DOM element or UiParam
 * @returns Telemetry data payload, or null if the element has no UI Identity
 */
export function trackUiInteraction(target: HTMLElement | UiParam | null): UiTelemetryData | null {
  const identity = resolveTelemetryIdentity(target);
  if (!identity) return null;

  const telemetryData: UiTelemetryData = {
    uuid: getUiIdentityUuid(identity),
    instanceId: target && typeof target === 'object' && 'getAttribute' in target
      ? target.getAttribute('data-ui-instance-id') || undefined
      : undefined,
    identityKey: target && typeof target === 'object' && 'getAttribute' in target
      ? target.getAttribute('data-ui-identity-key') || getUiIdentityUuid(identity)
      : getUiIdentityUuid(identity),
    id: identity.id,
    path: identity.path,
    feature: identity.feature,
    timestamp: new Date().toISOString(),
  };

  // Log telemetry in development mode
  if (process.env.NODE_ENV === 'development') {
    console.groupCollapsed(`[UI Telemetry] Interaction on "${identity.id}"`);
    console.log(`- Path: ${identity.path}`);
    console.log(`- UUID: ${getUiIdentityUuid(identity)}`);
    if (telemetryData.instanceId) {
      console.log(`- Instance: ${telemetryData.instanceId}`);
    }
    console.log(`- Feature: ${identity.feature}`);
    if (target && typeof target === 'object' && 'getAttribute' in target) {
      console.log(`- Element:`, target);
    }
    const sourceInfo = resolveElementIdentity(target);
    if (sourceInfo) {
      console.log(`- Source: ${sourceInfo.sourceComponent} (${sourceInfo.sourceFile}:${sourceInfo.sourceLine})`);
    }
    console.groupEnd();
  }

  return telemetryData;
}

/**
 * Track a view / exposure event.
 * 
 * @param target The DOM element or UiParam
 * @returns Telemetry data payload, or null if the element has no UI Identity
 */
export function trackUiView(target: HTMLElement | UiParam | null): UiTelemetryData | null {
  const identity = resolveTelemetryIdentity(target);
  if (!identity) return null;

  const telemetryData: UiTelemetryData = {
    uuid: getUiIdentityUuid(identity),
    instanceId: target && typeof target === 'object' && 'getAttribute' in target
      ? target.getAttribute('data-ui-instance-id') || undefined
      : undefined,
    identityKey: target && typeof target === 'object' && 'getAttribute' in target
      ? target.getAttribute('data-ui-identity-key') || getUiIdentityUuid(identity)
      : getUiIdentityUuid(identity),
    id: identity.id,
    path: identity.path,
    feature: identity.feature,
    timestamp: new Date().toISOString(),
  };

  // Log telemetry in development mode
  if (process.env.NODE_ENV === 'development') {
    console.groupCollapsed(`[UI Telemetry] View on "${identity.id}"`);
    console.log(`- Path: ${identity.path}`);
    console.log(`- UUID: ${getUiIdentityUuid(identity)}`);
    if (telemetryData.instanceId) {
      console.log(`- Instance: ${telemetryData.instanceId}`);
    }
    console.log(`- Feature: ${identity.feature}`);
    console.groupEnd();
  }

  return telemetryData;
}

/**
 * Track an error event occurring on a UI identity.
 * 
 * @param target The DOM element or UiParam
 * @param error The thrown error object
 * @returns Error telemetry payload, or null if target has no UI identity
 */
export function trackUiError(target: HTMLElement | UiParam | null, error: Error): UiErrorTelemetryData | null {
  const identity = resolveTelemetryIdentity(target);
  if (!identity) return null;

  const telemetryData: UiErrorTelemetryData = {
    uuid: getUiIdentityUuid(identity),
    instanceId: target && typeof target === 'object' && 'getAttribute' in target
      ? target.getAttribute('data-ui-instance-id') || undefined
      : undefined,
    identityKey: target && typeof target === 'object' && 'getAttribute' in target
      ? target.getAttribute('data-ui-identity-key') || getUiIdentityUuid(identity)
      : getUiIdentityUuid(identity),
    id: identity.id,
    path: identity.path,
    feature: identity.feature,
    timestamp: new Date().toISOString(),
    errorMessage: error.message,
    errorStack: error.stack,
  };

  // Log telemetry in development mode
  if (process.env.NODE_ENV === 'development') {
    console.groupCollapsed(`[UI Telemetry] ERROR on "${identity.id}"`);
    console.log(`- Path: ${identity.path}`);
    console.log(`- UUID: ${getUiIdentityUuid(identity)}`);
    if (telemetryData.instanceId) {
      console.log(`- Instance: ${telemetryData.instanceId}`);
    }
    console.log(`- Feature: ${identity.feature}`);
    console.error(`- Error: ${error.message}`, error);
    console.groupEnd();
  }

  return telemetryData;
}

