'use client';

import { useLayoutEffect, useRef, type ReactNode } from 'react';
import {
  initializeUnifiedStore,
  syncDOMFromStore,
  useUnifiedStore,
} from '@/store/unified.store';

interface UnifiedProviderProps {
  snapshot: {
    language: 'en' | 'ar';
    themeMode: 'light' | 'dark' | 'system';
    fontSize: number;
    density: 'compact' | 'comfortable' | 'spacious';
    highContrast: boolean;
    reducedMotion: boolean;
  };
  children: ReactNode;
}

/**
 * Seeds the client unified store from the server snapshot before hydration,
 * then rehydrates persisted preferences from localStorage.
 */
export function SSOTProvider({ snapshot, children }: UnifiedProviderProps) {
  const seeded = useRef(false);

  if (!seeded.current) {
    seeded.current = true;
    // Apply snapshot to store
    useUnifiedStore.setState({
      language: snapshot.language,
      themeMode: snapshot.themeMode,
      fontSize: snapshot.fontSize,
      density: snapshot.density,
      highContrast: snapshot.highContrast,
      reducedMotion: snapshot.reducedMotion,
      direction: snapshot.language === 'ar' ? 'rtl' : 'ltr',
    });
  }

  useLayoutEffect(() => {
    initializeUnifiedStore();

    const onFinishHydration = () => {
      const state = useUnifiedStore.getState();
      syncDOMFromStore(state);
    };

    const unsub = useUnifiedStore.persist.onFinishHydration(onFinishHydration);
    void useUnifiedStore.persist.rehydrate();

    return unsub;
  }, []);

  return <>{children}</>;
}

/**
 * Runtime Safety Layer
 * 
 * Detects runtime violations in DEV mode only
 * Warns about missing translations, UI bindings, and hardcoded text
 * NO PRODUCTION IMPACT
 */

import React from 'react';

const IS_DEV = process.env.NODE_ENV === 'development';

interface LegacyGuardWarning {
  type: 'missing_translation' | 'missing_ui_binding' | 'hardcoded_text';
  message: string;
  location: string | undefined;
  timestamp: number;
}

/**
 * Check if legacy guard is enabled
 */
export function isLegacyGuardEnabled(): boolean {
  return IS_DEV;
}

/**
 * Log a legacy guard warning
 */
function logWarning(warning: LegacyGuardWarning): void {
  if (!IS_DEV) {
    return;
  }
  
  console.warn(`ΓÜá∩╕Å  [LEGACY GUARD] ${warning.type.toUpperCase()}: ${warning.message}`);
  if (warning.location) {
    console.warn(`   Location: ${warning.location}`);
  }
}

/**
 * Warn about missing translation
 */
export function warnMissingTranslation(key: string, location?: string): void {
  if (!IS_DEV) {
    return;
  }
  
  const warning: LegacyGuardWarning = {
    type: 'missing_translation',
    message: `Translation key "${key}" is missing or not loaded`,
    location,
    timestamp: Date.now(),
  };
  
  logWarning(warning);
}

/**
 * Warn about missing UI binding
 */
export function warnMissingUiBinding(uiIdentifier: string, location?: string): void {
  if (!IS_DEV) {
    return;
  }
  
  const warning: LegacyGuardWarning = {
    type: 'missing_ui_binding',
    message: `UI identifier "${uiIdentifier}" is missing translation binding`,
    location,
    timestamp: Date.now(),
  };
  
  logWarning(warning);
}

/**
 * Warn about hardcoded text
 */
export function warnHardcodedText(text: string, location?: string): void {
  if (!IS_DEV) {
    return;
  }
  
  const warning: LegacyGuardWarning = {
    type: 'hardcoded_text',
    message: `Hardcoded text detected: "${text.substring(0, 50)}${text.length > 50 ? '...' : ''}"`,
    location,
    timestamp: Date.now(),
  };
  
  logWarning(warning);
}

/**
 * Validate translation key exists
 */
export function validateTranslationKey(key: string, availableKeys: Set<string>, location?: string): boolean {
  if (!IS_DEV) {
    return true; // Skip validation in production
  }
  
  if (!availableKeys.has(key)) {
    warnMissingTranslation(key, location);
    return false;
  }
  
  return true;
}

/**
 * Validate UI identifier has binding
 */
export function validateUiBinding(uiIdentifier: string, bindingMap: Record<string, string>, location?: string): boolean {
  if (!IS_DEV) {
    return true; // Skip validation in production
  }
  
  if (!bindingMap[uiIdentifier]) {
    warnMissingUiBinding(uiIdentifier, location);
    return false;
  }
  
  return true;
}

/**
 * Check for hardcoded text in JSX
 */
export function checkForHardcodedText(text: string, location?: string): boolean {
  if (!IS_DEV) {
    return true; // Skip validation in production
  }
  
  // Skip if it's too short or looks like code
  if (!text || text.length < 2 || /^[A-Z_\-0-9]+$/.test(text)) {
    return true;
  }
  
  warnHardcodedText(text, location);
  return false;
}

/**
 * Legacy guard hook for React components
 */
export function useLegacyGuard(componentName: string) {
  if (!IS_DEV) {
    return {
      warnMissingTranslation,
      warnMissingUiBinding,
      warnHardcodedText,
      validateTranslationKey,
      validateUiBinding,
      checkForHardcodedText,
    };
  }
  
  console.log(`≡ƒöì [LEGACY GUARD] Monitoring component: ${componentName}`);
  
  return {
    warnMissingTranslation: (key: string) => warnMissingTranslation(key, componentName),
    warnMissingUiBinding: (uiIdentifier: string) => warnMissingUiBinding(uiIdentifier, componentName),
    warnHardcodedText: (text: string) => warnHardcodedText(text, componentName),
    validateTranslationKey: (key: string, availableKeys: Set<string>) => 
      validateTranslationKey(key, availableKeys, componentName),
    validateUiBinding: (uiIdentifier: string, bindingMap: Record<string, string>) => 
      validateUiBinding(uiIdentifier, bindingMap, componentName),
    checkForHardcodedText: (text: string) => checkForHardcodedText(text, componentName),
  };
}

/**
 * Runtime validation wrapper for translation function
 */
export function createGuardedTranslationFunction(
  t: (key: string) => string,
  availableKeys: Set<string>,
  location?: string
): (key: string) => string {
  if (!IS_DEV) {
    return t; // No wrapping in production
  }
  
  return (key: string) => {
    validateTranslationKey(key, availableKeys, location);
    return t(key);
  };
}

/**
 * Runtime validation wrapper for UI component
 */
export function createGuardedUiComponent(
  Component: React.ComponentType<any>,
  bindingMap: Record<string, string>,
  location?: string
): React.ComponentType<any> {
  if (!IS_DEV) {
    return Component; // No wrapping in production
  }
  
  return function GuardedComponent(props: any) {
    const { ui } = props;
    
    if (ui) {
      validateUiBinding(ui, bindingMap, location);
    }
    
    return React.createElement(Component, props);
  };
}

/**
 * Get legacy guard statistics (DEV mode only)
 */
export function getLegacyGuardStats(): {
  enabled: boolean;
  warnings: LegacyGuardWarning[];
  totalWarnings: number;
  byType: Record<string, number>;
} {
  if (!IS_DEV) {
    return {
      enabled: false,
      warnings: [],
      totalWarnings: 0,
      byType: {},
    };
  }
  
  // In a real implementation, this would track warnings
  // For now, return empty stats
  return {
    enabled: true,
    warnings: [],
    totalWarnings: 0,
    byType: {},
  };
}

/**
 * Migration Queue System
 * 
 * Manages the progressive cleanup of legacy violations by organizing them
 * into a prioritized queue that can be processed feature-by-feature.
 */

import { readFileSync, existsSync } from 'fs';
import { join } from 'path';

export interface LegacyViolation {
  id: string;
  type: 'hardcoded_text' | 'missing_ui_identifier' | 'missing_translation' | 'missing_binding';
  severity: 'CRITICAL' | 'HIGH' | 'MEDIUM' | 'LOW';
  file: string;
  line: number;
  column: number;
  feature: string;
  description: string;
  suggestion: string;
  autoFixable: boolean;
  status?: 'pending' | 'in_progress' | 'fixed' | 'skipped' | 'blocked';
}

export interface MigrationQueue {
  violations: LegacyViolation[];
  byFeature: Record<string, LegacyViolation[]>;
  bySeverity: Record<string, LegacyViolation[]>;
  total: number;
  pending: number;
  inProgress: number;
  fixed: number;
  skipped: number;
  blocked: number;
}

export interface FeatureMigrationStatus {
  feature: string;
  totalViolations: number;
  critical: number;
  high: number;
  medium: number;
  low: number;
  autoFixable: number;
  manualFixRequired: number;
  status: 'pending' | 'in_progress' | 'completed' | 'blocked';
  progress: number;
}

const SEVERITY_ORDER = ['CRITICAL', 'HIGH', 'MEDIUM', 'LOW'];
const FEATURE_ORDER = ['auth', 'home', 'dashboard', 'settings', 'splash', 'common'];

/**
 * Load violations from the legacy violation report
 */
export function loadViolations(): LegacyViolation[] {
  const reportPath = join(process.cwd(), 'docs', 'migration', 'legacy-violations-report.json');
  
  if (!existsSync(reportPath)) {
    console.warn('Legacy violation report not found. Run scan-legacy-violations first.');
    return [];
  }
  
  try {
    const content = readFileSync(reportPath, 'utf-8');
    const report = JSON.parse(content);
    return report.violations || [];
  } catch (error) {
    console.error('Error loading violation report:', error);
    return [];
  }
}

/**
 * Build migration queue from violations
 */
export function buildMigrationQueue(violations: LegacyViolation[]): MigrationQueue {
  const byFeature: Record<string, LegacyViolation[]> = {};
  const bySeverity: Record<string, LegacyViolation[]> = {};
  
  // Initialize with all features
  for (const feature of FEATURE_ORDER) {
    byFeature[feature] = [];
  }
  
  // Group violations by feature and severity
  for (const violation of violations) {
    const feature = violation.feature || 'common';
    if (!byFeature[feature]) {
      byFeature[feature] = [];
    }
    byFeature[feature].push(violation);
    
    const severity = violation.severity;
    if (!bySeverity[severity]) {
      bySeverity[severity] = [];
    }
    bySeverity[severity].push(violation);
    
    // Set default status
    if (!violation.status) {
      violation.status = 'pending';
    }
  }
  
  // Sort violations within each feature by severity
  for (const feature in byFeature) {
    byFeature[feature].sort((a, b) => {
      const severityA = SEVERITY_ORDER.indexOf(a.severity);
      const severityB = SEVERITY_ORDER.indexOf(b.severity);
      return severityA - severityB;
    });
  }
  
  // Sort violations within each severity by feature order
  for (const severityKey in bySeverity) {
    bySeverity[severityKey].sort((a, b) => {
      const featureA = FEATURE_ORDER.indexOf(a.feature);
      const featureB = FEATURE_ORDER.indexOf(b.feature);
      return featureA - featureB;
    });
  }
  
  // Calculate statistics
  const total = violations.length;
  const pending = violations.filter(v => v.status === 'pending').length;
  const inProgress = violations.filter(v => v.status === 'in_progress').length;
  const fixed = violations.filter(v => v.status === 'fixed').length;
  const skipped = violations.filter(v => v.status === 'skipped').length;
  const blocked = violations.filter(v => v.status === 'blocked').length;
  
  return {
    violations,
    byFeature,
    bySeverity,
    total,
    pending,
    inProgress,
    fixed,
    skipped,
    blocked,
  };
}

/**
 * Get feature migration status
 */
export function getFeatureMigrationStatus(queue: MigrationQueue, feature: string): FeatureMigrationStatus {
  const featureViolations = queue.byFeature[feature] || [];
  
  const critical = featureViolations.filter(v => v.severity === 'CRITICAL').length;
  const high = featureViolations.filter(v => v.severity === 'HIGH').length;
  const medium = featureViolations.filter(v => v.severity === 'MEDIUM').length;
  const low = featureViolations.filter(v => v.severity === 'LOW').length;
  const autoFixable = featureViolations.filter(v => v.autoFixable).length;
  const manualFixRequired = featureViolations.filter(v => !v.autoFixable).length;
  
  const fixed = featureViolations.filter(v => v.status === 'fixed').length;
  const progress = featureViolations.length > 0 ? (fixed / featureViolations.length) * 100 : 100;
  
  let status: 'pending' | 'in_progress' | 'completed' | 'blocked' = 'pending';
  if (progress === 100) {
    status = 'completed';
  } else if (fixed > 0) {
    status = 'in_progress';
  }
  
  return {
    feature,
    totalViolations: featureViolations.length,
    critical,
    high,
    medium,
    low,
    autoFixable,
    manualFixRequired,
    status,
    progress,
  };
}

/**
 * Get next violation to process
 */
export function getNextViolation(queue: MigrationQueue): LegacyViolation | null {
  // Find first pending violation by priority
  for (const _severity of SEVERITY_ORDER) {
    for (const feature of FEATURE_ORDER) {
      const featureViolations = queue.byFeature[feature] || [];
      const pending = featureViolations.find(v => v.status === 'pending');
      if (pending) {
        return pending;
      }
    }
  }
  
  return null;
}

/**
 * Mark violation as fixed
 */
export function markViolationFixed(queue: MigrationQueue, violationId: string): boolean {
  const violation = queue.violations.find(v => v.id === violationId);
  if (violation) {
    violation.status = 'fixed';
    return true;
  }
  return false;
}

/**
 * Mark violation as in progress
 */
export function markViolationInProgress(queue: MigrationQueue, violationId: string): boolean {
  const violation = queue.violations.find(v => v.id === violationId);
  if (violation) {
    violation.status = 'in_progress';
    return true;
  }
  return false;
}

/**
 * Mark violation as skipped
 */
export function markViolationSkipped(queue: MigrationQueue, violationId: string, reason?: string): boolean {
  const violation = queue.violations.find(v => v.id === violationId);
  if (violation) {
    violation.status = 'skipped';
    if (reason) {
      violation.description += ` (Skipped: ${reason})`;
    }
    return true;
  }
  return false;
}

/**
 * Mark violation as blocked
 */
export function markViolationBlocked(queue: MigrationQueue, violationId: string, reason?: string): boolean {
  const violation = queue.violations.find(v => v.id === violationId);
  if (violation) {
    violation.status = 'blocked';
    if (reason) {
      violation.description += ` (Blocked: ${reason})`;
    }
    return true;
  }
  return false;
}

/**
 * Get violations for a specific feature
 */
export function getFeatureViolations(queue: MigrationQueue, feature: string): LegacyViolation[] {
  return queue.byFeature[feature] || [];
}

/**
 * Get violations by severity
 */
export function getSeverityViolations(queue: MigrationQueue, severity: string): LegacyViolation[] {
  return queue.bySeverity[severity] || [];
}

/**
 * Get auto-fixable violations
 */
export function getAutoFixableViolations(queue: MigrationQueue): LegacyViolation[] {
  return queue.violations.filter(v => v.autoFixable && v.status === 'pending');
}

/**
 * Get manual fix violations
 */
export function getManualFixViolations(queue: MigrationQueue): LegacyViolation[] {
  return queue.violations.filter(v => !v.autoFixable && v.status === 'pending');
}

/**
 * Calculate overall migration progress
 */
export function calculateMigrationProgress(queue: MigrationQueue): number {
  if (queue.total === 0) {
    return 100;
  }
  return (queue.fixed / queue.total) * 100;
}

/**
 * Get migration summary
 */
export function getMigrationSummary(queue: MigrationQueue): {
  totalViolations: number;
  completed: number;
  remaining: number;
  progress: number;
  byFeature: Record<string, FeatureMigrationStatus>;
  bySeverity: Record<string, number>;
} {
  const byFeature: Record<string, FeatureMigrationStatus> = {};
  
  for (const feature of FEATURE_ORDER) {
    byFeature[feature] = getFeatureMigrationStatus(queue, feature);
  }
  
  const bySeverity: Record<string, number> = {};
  for (const severityKey of SEVERITY_ORDER) {
    bySeverity[severityKey] = (queue.bySeverity[severityKey] || []).length;
  }
  
  return {
    totalViolations: queue.total,
    completed: queue.fixed,
    remaining: queue.pending + queue.inProgress,
    progress: calculateMigrationProgress(queue),
    byFeature,
    bySeverity,
  };
}

/**
 * Save migration queue state
 */
export function saveMigrationQueue(queue: MigrationQueue): void {
  // eslint-disable-next-line @typescript-eslint/no-require-imports
  const fs = require('fs');
  const queuePath = join(process.cwd(), 'docs', 'migration', 'migration-queue.json');
  fs.writeFileSync(queuePath, JSON.stringify(queue, null, 2), 'utf-8');
  console.log(`Migration queue saved to ${queuePath}`);
}

/**
 * Load migration queue state
 */
export function loadMigrationQueue(): MigrationQueue | null {
  const queuePath = join(process.cwd(), 'docs', 'migration', 'migration-queue.json');
  
  if (!existsSync(queuePath)) {
    return null;
  }
  
  try {
    // eslint-disable-next-line @typescript-eslint/no-require-imports
    const fs = require('fs');
    const content = fs.readFileSync(queuePath, 'utf-8');
    return JSON.parse(content);
  } catch (error) {
    console.error('Error loading migration queue:', error);
    return null;
  }
}

